var documenterSearchIndex = {"docs":
[{"category":"section","location":"generated/muca_OU/#Large-Deviations-of-the-Ornstein–Uhlenbeck-Process","page":"Multicanonical: Ornstein-Uhlenbeck","text":"The Ornstein–Uhlenbeck (OU) process is a continuous-time stochastic process with mean-reverting drift:\n\ndx_t = theta(mu - x_t)dt + sigmadW_t\n\nwhere mu is the long-time mean, theta the inverse relaxation timescale, sigma = sqrt2D the noise amplitude, and dW_t sim mathcalN(0 dt) a Wiener increment.\n\nThe terminal value x(T) is Gaussian with known mean and variance, providing an exact reference against which we validate three sampling strategies: direct sampling, biased Metropolis, and multicanonical iteration.\n\nusing Random, Distributions, StatsBase, LinearAlgebra\nusing MonteCarloX\nusing Plots, ProgressMeter","title":"Large Deviations of the Ornstein–Uhlenbeck Process"},{"category":"section","location":"generated/muca_OU/#Parameters","page":"Multicanonical: Ornstein-Uhlenbeck","text":"μ, D, θ  = 0.0, 1.0, 1.0\ndt, T, x0 = 0.1, 10.0, 0.0\n\nconst CI_MODE = get(ENV, \"MCX_SMOKE\", get(ENV, \"MCX_CI\", \"false\")) == \"true\"\nn_direct   = CI_MODE ? 1_000    : 100_000\nn_therm    = CI_MODE ? 100      : 10_000\nn_metro    = CI_MODE ? 1_000    : 1_000_000\nn_muca     = CI_MODE ? 1_000    : 10_000_000\nn_iter     = CI_MODE ? 3        : 10\nn_iter_steps = CI_MODE ? 1_000  : 5_000_000;\n# exact terminal distribution (see Wikipedia: OU process)\nmean_T = x0 * exp(-T*θ) + μ * (1 - exp(-T*θ))\nvar_T  = θ < 1e-6 ? 2*D*T : D/θ * (1 - exp(-2*T*θ))\nstd_T  = sqrt(var_T)\npdf_T  = Normal(mean_T, std_T)\n\nbins_T    = (mean_T - 10*std_T) : (std_T/10) : (mean_T + 10*std_T)\ncenters_T = collect(bins_T[1:end-1] .+ diff(collect(bins_T))./2)\nlogpdf_T  = logpdf.(pdf_T, centers_T)\n\nprintln(\"Terminal distribution: mean = $(mean_T),  std = $(round(std_T; digits=3))\")","title":"Parameters"},{"category":"section","location":"generated/muca_OU/#Trajectory-system","page":"Multicanonical: Ornstein-Uhlenbeck","text":"The state is a full discretised trajectory dW_t of Wiener increments. Each update proposes a change to one randomly chosen increment, accepts it under the Gaussian prior (Metropolis-within-Gibbs), then accepts or rejects based on the terminal value x(T) via the sampling algorithm.\n\nmutable struct OUTrajectory\n    ts        :: Vector{Float64}\n    xs        :: Vector{Float64}\n    dWs       :: Vector{Float64}\n    tmp_xs    :: Vector{Float64}\n    tmp_dWs   :: Vector{Float64}\n    logpdf_dW :: Function\n    μ :: Float64;  σ :: Float64\n    θ :: Float64;  dt :: Float64\n    function OUTrajectory(rng; x0=0.0, μ=0.0, D=1.0, θ=1.0, dt=0.1, T=10.0)\n        N    = round(Int, T/dt) + 1\n        σ    = sqrt(2*D)\n        dist = Normal(0, sqrt(dt))\n        dWs  = rand(rng, dist, N)\n        xs   = zeros(N)\n        ts   = collect(0:dt:(N-1)*dt)\n        sys  = new(ts, xs, dWs, zeros(N), zeros(N),\n                   x -> logpdf(dist, x), μ, σ, θ, dt)\n        sys.xs[1] = x0\n        integrate!(sys)\n        return sys\n    end\nend\n\n@inline function integrate!(sys::OUTrajectory, r::UnitRange{Int}=1:0)\n    r = isempty(r) ? (1:length(sys.xs)) : r\n    x = sys.xs[first(r)]\n    for i in first(r):last(r)-1\n        x += sys.θ*(sys.μ - x)*sys.dt + sys.σ*sys.dWs[i]\n        sys.xs[i+1] = x\n    end\nend\n\nx_T(sys::OUTrajectory) = sys.xs[end]\n\nfunction update!(sys::OUTrajectory, alg::AbstractImportanceSampling; δ=0.5)\n    idx    = rand(alg.rng, 1:length(sys.dWs))\n    dW_old = sys.dWs[idx]\n    dW_new = dW_old + δ * (2*rand(alg.rng) - 1)\n    # accept under Gaussian prior first\n    if rand(alg.rng) < exp(sys.logpdf_dW(dW_new) - sys.logpdf_dW(dW_old))\n        sys.tmp_xs[idx:end]  .= sys.xs[idx:end]\n        sys.tmp_dWs[idx:end] .= sys.dWs[idx:end]\n        sys.dWs[idx] = dW_new\n        integrate!(sys, idx:length(sys.xs))\n        if !accept!(alg, sys.xs[end], sys.tmp_xs[end])\n            sys.xs[idx:end]  .= sys.tmp_xs[idx:end]\n            sys.dWs[idx:end] .= sys.tmp_dWs[idx:end]\n        end\n    else\n        alg.steps += 1\n    end\nend\n\n# visualise a single trajectory\nsys0 = OUTrajectory(MersenneTwister(1234); x0=x0, μ=μ, D=D, θ=θ, dt=dt, T=T)\nplot(sys0.ts, sys0.xs; label=nothing, xlabel=\"Time\", ylabel=\"x\",\n     title=\"Single OU trajectory\", size=(700, 220), margin=5Plots.mm)","title":"Trajectory system"},{"category":"section","location":"generated/muca_OU/#Direct-sampling","page":"Multicanonical: Ornstein-Uhlenbeck","text":"We draw 10^5 independent trajectories and record x(T) as a reference.\n\ndirect_samples = [OUTrajectory(MersenneTwister(i); x0=x0, μ=μ, D=D, θ=θ,\n                               dt=dt, T=T).xs[end] for i in 1:n_direct]\nhist_direct = normalize(fit(Histogram, direct_samples, bins_T); mode=:pdf)\n\nplot(hist_direct; st=:bar, linewidth=0, alpha=0.6,\n     label=\"Direct samples\", xlabel=\"x(T)\", ylabel=\"Density\",\n     title=\"Terminal distribution vs exact\", size=(600, 250), margin=5Plots.mm)\nplot!(centers_T, pdf.(pdf_T, centers_T); lw=2, color=:black, ls=:dash, label=\"Exact\")","title":"Direct sampling"},{"category":"section","location":"generated/muca_OU/#Importance-sampling-with-Metropolis","page":"Multicanonical: Ornstein-Uhlenbeck","text":"A biasing field beta exponentially enhances trajectories ending at large (beta  0) or small (beta  0) values of x(T), giving direct access to the tails of the distribution.\n\nfunction run_metropolis(; β=0.0)\n    sys  = OUTrajectory(MersenneTwister(123); x0=x0, μ=μ, D=D, θ=θ, dt=dt, T=T)\n    alg  = Metropolis(MersenneTwister(42); β=β)\n    meas_ts   = Measurements([:x_T => x_T => Float64[]], interval=100)\n    meas_hist = Measurements([:x_T => x_T => fit(Histogram, [], bins_T)], interval=1)\n    for _ in 1:n_therm;  update!(sys, alg); end\n    for i in 1:n_metro\n        update!(sys, alg)\n        measure!(meas_hist, sys, i)\n        measure!(meas_ts,   sys, i)\n    end\n    println(\"β = $(β):  acceptance = \", round(acceptance_rate(alg); digits=3))\n    return meas_ts, meas_hist, sys\nend\n\nβs      = [0.0, 3.0, 6.0]\nresults = Dict(β => run_metropolis(β=β) for β in βs)\n\n# time series — shows how β shifts the explored region\np_ts = plot(xlabel=\"Iteration\", ylabel=\"x(T)\", title=\"Time series\",\n            legend=:topleft, size=(600, 220), margin=5Plots.mm)\nfor β in βs\n    plot!(p_ts, results[β][1][:x_T].data; label=\"β=$β\", lw=1)\nend\np_ts","title":"Importance sampling with Metropolis"},{"category":"section","location":"generated/muca_OU/#Terminal-distributions-under-biasing","page":"Multicanonical: Ornstein-Uhlenbeck","text":"Each beta samples a different part of the tail. Together they cover the full distribution including the exponentially rare large-x(T) events.\n\np_dist = plot(centers_T, pdf.(pdf_T, centers_T);\n              lw=2, color=:black, ls=:dash, label=\"Exact\",\n              xlabel=\"x(T)\", ylabel=\"Density\",\n              title=\"Biased distributions\", size=(600, 250), margin=5Plots.mm)\nfor β in βs\n    w    = results[β][2][:x_T].data.weights\n    norm = sum(w) * step(bins_T)\n    plot!(p_dist, centers_T, w ./ norm; lw=2, label=\"β=$β\")\nend\np_dist","title":"Terminal distributions under biasing"},{"category":"section","location":"generated/muca_OU/#Biased-trajectories","page":"Multicanonical: Ornstein-Uhlenbeck","text":"Larger beta shifts the ensemble of trajectories toward systematically higher terminal values, revealing the rare fluctuation pathways.\n\np_traj = plot(xlabel=\"Time\", ylabel=\"x\", title=\"Typical trajectories per β\",\n              size=(700, 260), margin=5Plots.mm)\np_dW   = plot(xlabel=\"Time\", ylabel=\"dW\", title=\"Wiener increments\",\n              size=(700, 260), margin=5Plots.mm)\nfor β in βs\n    sys = results[β][3]\n    plot!(p_traj, sys.ts, sys.xs;  label=\"β=$β\")\n    plot!(p_dW,   sys.ts, sys.dWs; label=\"β=$β\")\n    println(\"β=$β:  mean x = \", round(mean(sys.xs); digits=3),\n                   \"  mean dW = \", round(mean(sys.dWs); digits=3))\nend\nplot(p_traj, p_dW; layout=(2,1), size=(700, 420), margin=5Plots.mm)","title":"Biased trajectories"},{"category":"section","location":"generated/muca_OU/#Multicanonical-sampling-—-flat-histogram","page":"Multicanonical: Ornstein-Uhlenbeck","text":"With flat weights the algorithm samples x(T) uniformly across the full support, independently of the shape of the distribution.\n\nsys_muca0  = OUTrajectory(MersenneTwister(123); x0=x0, μ=μ, D=D, θ=θ, dt=dt, T=T)\nalg_muca0  = Multicanonical(MersenneTwister(100), BinnedObject(bins_T, 0.0))\nmeas_muca0 = Measurements([:x_T => x_T => fit(Histogram, [], bins_T)], interval=1)\n\nfor _ in 1:n_therm;  update!(sys_muca0, alg_muca0); end\nfor i in 1:n_muca;   update!(sys_muca0, alg_muca0); measure!(meas_muca0, sys_muca0, i); end\nprintln(\"MUCA (flat):  acceptance = \", round(acceptance_rate(alg_muca0); digits=3))\n\nw0   = meas_muca0[:x_T].data.weights\nnorm0 = sum(w0) * step(bins_T)\nplot(centers_T, w0 ./ norm0; lw=2, label=\"MUCA (flat)\",\n     xlabel=\"x(T)\", ylabel=\"Density\",\n     title=\"Flat-weight multicanonical\", size=(600, 250), margin=5Plots.mm)\nplot!(centers_T, pdf.(pdf_T, centers_T); lw=2, color=:black, ls=:dash, label=\"Exact\")","title":"Multicanonical sampling — flat histogram"},{"category":"section","location":"generated/muca_OU/#Multicanonical-iteration","page":"Multicanonical: Ornstein-Uhlenbeck","text":"Starting from flat weights, the algorithm iteratively learns the log-DOS. Linear boundary tails prevent the chain escaping the binned region.\n\nsys_iter = OUTrajectory(MersenneTwister(42); x0=x0, μ=μ, D=D, θ=θ, dt=dt, T=T)\nalg_iter = Multicanonical(MersenneTwister(42), BinnedObject(bins_T, 0.0))\n\nn_iter      = 10\niter_hists  = typeof(ensemble(alg_iter).histogram)[]\niter_lws    = typeof(logweight(alg_iter))[]\niter_accept = Float64[]\n\nx_left  = first(bins_T) + std_T\nx_right = last(bins_T)  - std_T\ncs      = get_centers(logweight(alg_iter))\n\n@showprogress 1 \"Iterating MUCA...\" for _ in 1:n_iter\n    for _ in 1:n_therm;    update!(sys_iter, alg_iter; δ=0.5); end\n    reset!(alg_iter)\n    for _ in 1:n_iter_steps; update!(sys_iter, alg_iter; δ=0.5); end\n\n    MonteCarloX.update!(ensemble(alg_iter); mode=:simple)\n\n    # reapply linear boundary tails\n    set!(logweight(alg_iter), (first(cs), x_left),\n         x -> logweight(alg_iter)(x_left)  + (x - x_left)  * 2.0)\n    set!(logweight(alg_iter), (x_right, last(cs)),\n         x -> logweight(alg_iter)(x_right) - (x - x_right) * 2.0)\n\n    push!(iter_hists,  deepcopy(ensemble(alg_iter).histogram))\n    push!(iter_lws,    deepcopy(logweight(alg_iter)))\n    push!(iter_accept, acceptance_rate(alg_iter))\nend\n\nplot(iter_accept; xlabel=\"Iteration\", ylabel=\"Acceptance rate\",\n     title=\"Convergence of acceptance rate\", label=nothing,\n     size=(600, 220), margin=5Plots.mm)","title":"Multicanonical iteration"},{"category":"section","location":"generated/muca_OU/#Plotting-convergence-of-histogram-and-log-DOS","page":"Multicanonical: Ornstein-Uhlenbeck","text":"Each iteration refines the log-DOS estimate toward the exact reference.\n\nfunction plot_muca_convergence(hists, lws; xlabel=\"x(T)\")\n    n    = length(hists)\n    cols = palette(:viridis, max(n,2))[1:n]\n    i0   = searchsortedlast(centers_T, 0.0)\n\n    p1 = plot(xlabel=xlabel, ylabel=\"Counts\", title=\"Histograms\", legend=false)\n    for i in 1:n\n        plot!(p1, centers_T, hists[i].values; lw=2, color=cols[i])\n    end\n\n    p2 = plot(xlabel=xlabel, ylabel=\"-log w\", title=\"Log-DOS vs exact\",\n              legend=:topright)\n    for i in 1:n\n        w = -lws[i].values .+ lws[i](0.0)\n        plot!(p2, centers_T, w; lw=2, color=cols[i], label=\"\")\n    end\n    plot!(p2, centers_T, logpdf_T .- logpdf_T[i0];\n          lw=2, color=:black, ls=:dash, label=\"Exact\")\n\n    return plot(p1, p2; layout=(1,2), size=(900, 280), margin=4Plots.mm)\nend\n\nplot_muca_convergence(iter_hists, iter_lws)\n\n\n\nThis page was generated using Literate.jl.","title":"Plotting convergence of histogram and log-DOS"},{"category":"section","location":"generated/parallel_chains_threads/#Parallel-Chains-(Threads)","page":"Parallel Chains (Threads)","text":"Run parallel Markov chains with a thread-based backend. Launch with:\n\njulia --threads=4 --project docs/src/examples/infrastructure/parallel_chains_threads.jl\n\nWith only a single chain this fails due to replica-exchange requirements nthreads>=2;\n\nFor the MPI version (HPC clusters), see parallel_chains_mpi.jl.\n\nKey differences from the MPI version (kept visible on purpose):\n\nOperates explicitly on vector of alg and vector of sys;\nData is stored in shared memory and can be accessed by threads;\nParallelization needs to be actively enabled via with_parallel or Threads.@threads;\nMonteCarloX API on parallel chain uses vectors of objects directly in shared memory\n\nusing Random, Statistics, StatsBase, Plots, ProgressMeter\nusing MonteCarloX","title":"Parallel Chains (Threads)"},{"category":"section","location":"generated/parallel_chains_threads/#Setup","page":"Parallel Chains (Threads)","text":"We sample a double-well potential E(x) = (x^2 - 1)^2 with minima at x = pm 1.  At low temperature a single chain gets trapped in one well; parallel tempering enables barrier crossings.\n\nconst CI_MODE = get(ENV, \"MCX_SMOKE\", get(ENV, \"MCX_CI\", \"false\")) == \"true\"\n\nmutable struct System\n    x::Float64\nend\n\nE(x::Real) = 1/4*(x^2 - 2)^2\nE(sys::System) = E(sys.x)\n\nfunction update!(sys::System, alg::AbstractImportanceSampling; delta=0.1)\n    x_new = sys.x + delta * randn(alg.rng)\n    accept!(alg, E(x_new), E(sys)) && (sys.x = x_new)\nend\n\nxbins = -3:0.01:3\nE_min = floor(minimum(E.(xbins)))\nE_max = ceil(maximum(E.(xbins)))\nEbins = E_min:0.005:E_max","title":"Setup"},{"category":"section","location":"generated/parallel_chains_threads/#Parameters","page":"Parallel Chains (Threads)","text":"n_samples = CI_MODE ? 50 : 50_000\nn_burn_in = CI_MODE ? 10 : 500\nn_sweep   = CI_MODE ? 10 : 100\nn_iter    = CI_MODE ? 2 : 6\n\nbackend  = ThreadsBackend()\nbeta_ref = 10.0\nbetas_pt = set_betas(size(backend), 0.1, beta_ref, :geometric)","title":"Parameters"},{"category":"section","location":"generated/parallel_chains_threads/#Independent-parallel-chains","page":"Parallel Chains (Threads)","text":"Each chain samples the same target independently. At high beta (low temperature) each chain gets trapped in whichever well it starts near. Merging samples from all chains does NOT fix this — you just get a biased mixture of trapped chains.\n\npc_algs = [Metropolis(Xoshiro(1000 + i); β=beta_ref) for i in 1:size(backend)]\npc      = ParallelChains(backend, pc_algs)\npc_sys  = [System(0.0) for i in 1:size(backend)]\n\nshared memory storage: each thread writes to its own row, no synchronization needed.\n\npc_xs = zeros(Float64, size(backend), n_samples)\npc_Es = zeros(Float64, size(backend), n_samples)\n\ntime = @elapsed with_parallel(pc) do i, alg\n    sys = pc_sys[i]\n    for _ in 1:n_burn_in\n        for _ in 1:n_sweep; update!(sys, alg); end\n    end\n    reset!(alg)\n    for j in 1:n_samples\n        for _ in 1:n_sweep; update!(sys, alg); end\n        pc_xs[i, j] = sys.x\n        pc_Es[i, j] = E(sys)\n    end\nend\n\nNo need to merge samples, we have shared memory\n\non_root(pc) do\n    println(\"## Independent chains (beta=$beta_ref) took $(round(time; digits=2)) seconds\")\n    for i in 1:size(pc)\n        println(\"  chain $i: mean_x=$(round(mean(pc_xs[i,:]); digits=3)), mean_E=$(round(mean(pc_Es[i,:]); digits=3))\")\n    end\n    println(\"  merged:  mean_x=$(round(mean(pc_xs); digits=3)), mean_E=$(round(mean(pc_Es); digits=3))\")\nend","title":"Independent parallel chains"},{"category":"section","location":"generated/parallel_chains_threads/#Parallel-tempering","page":"Parallel Chains (Threads)","text":"Same potential, same number of samples, but now replicas at different temperatures exchange configurations.  High-temperature replicas cross the barrier freely; exchanges propagate this to the cold replica, producing correct bimodal sampling even at high beta.\n\npt_algs = [Metropolis(Xoshiro(2000 + i); β=betas_pt[i]) for i in 1:size(backend)]\npt      = ParallelTempering(backend, pt_algs)\npt_sys  = [System(0.0) for _ in 1:size(pt)]\n\nglobal storage\n\npt_xs = zeros(Float64, size(pt), n_samples)\npt_Es = zeros(Float64, size(pt), n_samples)\n\nexchange_after_sample = 100\ntime = @elapsed for s in 1:Int(n_samples / exchange_after_sample)\n    with_parallel(pt) do i, alg\n        sys = pt_sys[i]\n        for _ in 1:n_burn_in\n            for _ in 1:n_sweep; update!(sys, alg); end\n        end\n        reset!(alg)\n        for j in 1:exchange_after_sample\n            for _ in 1:n_sweep; update!(sys, alg); end\n            pt_xs[index(pt, i), (s-1)*exchange_after_sample + j] = sys.x\n            pt_Es[index(pt, i), (s-1)*exchange_after_sample + j] = E(sys)\n        end\n    end\n\nreplica exchange gets full energy array, here we are no longer parallel\n\n    MonteCarloX.update!(pt, E.(pt_sys))\nend\n\nNo need to gather samples, we have shared memory\n\non_root(pt) do _\n    println(\"\\n## Parallel Tempering (betas = $(round.(betas_pt; digits=2))) took $(round(time; digits=2)) seconds\")\n    println(\"Exchange acceptance rates: \", round.(acceptance_rates(pt); digits=3))\n    for (i, b) in enumerate(betas_pt)\n        s = pt_xs[i, :]\n        println(\"  beta=$(round(b; digits=2)): $(length(s)) samples, mean=$(round(mean(s); digits=3)), std=$(round(std(s); digits=3))\")\n    end\nend","title":"Parallel tempering"},{"category":"section","location":"generated/parallel_chains_threads/#Multicanonical-sampling-with-parallel-chains","page":"Parallel Chains (Threads)","text":"Each chain runs a multicanonical sampler; after each iteration we merge histograms to root, refine the logweight on root, and distribute the new logweight back to all chains.\n\npmuca_algs = [Multicanonical(Xoshiro(3000 + i), Ebins) for i in 1:size(backend)]\npmuca      = ParallelMulticanonical(backend, pmuca_algs)\npmuca_sys  = [System(0.0) for i in 1:size(backend)]\n\nInitialize logweights with low temperature so chains stay in-range and the first histogram merge has non-zero counts.\n\nbeta_bound = beta_ref * 2\non_root(pmuca) do i\n    alg = algorithm(pmuca, i)\n    set!(logweight(alg), E -> -beta_bound * E)\nend\ndistribute_logweight!(pmuca)\n\nE_left  = 0.0\nE_right = 3.0\n\nprog = is_root(pmuca) ? Progress(n_iter; desc=\"pmuca iter\") : nothing\ntime_iter = @elapsed for iter in 1:n_iter\n    Threads.@threads for i in 1:size(pmuca)\n        alg = algorithm(pmuca, i)\n        sys = pmuca_sys[i]\n        for _ in 1:n_burn_in\n            for _ in 1:n_sweep; update!(sys, alg, delta=0.05); end\n        end\n        reset!(alg)\n        for j in 1:Int(round(n_samples / n_iter * iter))\n            for _ in 1:n_sweep; update!(sys, alg, delta=0.05); end\n        end\n    end\n    merge_histograms!(pmuca)\n    on_root(pmuca) do i\n        alg = algorithm(pmuca, i)\n        MonteCarloX.update!(ensemble(alg); mode=:simple)\n        set!(logweight(alg), (E_right, E_max),\n             E -> logweight(alg)(E_right) - beta_bound * (E - E_right))\n        next!(prog)\n    end\n    distribute_logweight!(pmuca)\nend\n\nProduction run with final weights.\n\npmuca_xs = zeros(Float64, size(pmuca), n_samples)\npmuca_Es = zeros(Float64, size(pmuca), n_samples)\ntime_prod = @elapsed with_parallel(pmuca) do i, alg\n    sys = pmuca_sys[i]\n    for j in 1:n_samples\n        for _ in 1:n_sweep; update!(sys, alg, delta=0.05); end\n        pmuca_xs[i, j] = sys.x\n        pmuca_Es[i, j] = E(sys)\n    end\nend\n\nNo need to gather samples, we have shared memory.\n\npmuca_xs = vec(pmuca_xs)\npmuca_Es = vec(pmuca_Es)\n\non_root(pmuca) do\n    println(\"\\n## Parallel Multicanonical took $(round(time_iter; digits=2)) seconds for iterations and $(round(time_prod; digits=2)) seconds for production runs\")\n    println(\"Acceptance rates (per chain): \",\n            round.([acceptance_rate(algorithm(pmuca, i)) for i in 1:size(pmuca)]; digits=2))\nend","title":"Multicanonical sampling with parallel chains"},{"category":"section","location":"generated/parallel_chains_threads/#Comparison-plot","page":"Parallel Chains (Threads)","text":"Independent chains at high beta get trapped in one well. Parallel tempering at the same beta recovers the bimodal distribution. The plotting is wrapped in a function so all c, w assignments live in hard scope (no soft-scope warnings).\n\nusing StatsBase, LinearAlgebra\n\nfunction make_comparison_plot(;\n        pt_cold_xs, pt_cold_Es,              # single-chain vectors at the cold beta\n        pc_chain_xs, pc_chain_Es,            # Vector-of-Vector, one per chain\n        pmuca_xs, pmuca_Es,                  # flat vectors (all samples)\n        lw_muca, beta_ref, xbins, Ebins)\n    col_true, col_pt, col_pc, col_muca = :black, :steelblue, :crimson, :forestgreen\n    centers(e) = e[1:end-1] .+ step(e)/2\n    xs_exact   = collect(-3:0.0001:3)\n    n_pc       = length(pc_chain_xs)\n\n    function pdf_hist(samples, bins; logw=nothing)\n        h = logw === nothing ? fit(Histogram, samples, bins) :\n            fit(Histogram, samples, Weights(exp.(logw .- maximum(logw))), bins)\n        return centers(bins), normalize(h; mode=:pdf).weights\n    end\n\npanel for P(x)\n\n    px = plot(xlabel=\"x\", ylabel=\"P(x)\", legend=false)\n    c, w = pdf_hist(pt_cold_xs, xbins); plot!(px, c, w; color=col_pt, lw=5)\n    for i in 1:n_pc\n        c, w = pdf_hist(pc_chain_xs[i], xbins); plot!(px, c, w; color=col_pc, alpha=i/n_pc, lw=2)\n    end\n    c, w = pdf_hist(pmuca_xs, xbins); plot!(px, c, w; color=col_muca, lw=2)\n    c, w = pdf_hist(pmuca_xs, xbins; logw=-beta_ref .* pmuca_Es .- lw_muca.(pmuca_Es))\n    plot!(px, c, w; color=col_muca, lw=4)\n    c, w = pdf_hist(xs_exact, xbins; logw=-beta_ref .* E.(xs_exact))\n    plot!(px, c, w; color=col_true, lw=2)\n\npanel for P(E)\n\n    pE = plot(xlabel=\"E\", ylabel=\"P(E)\", legend=false)\n    c, w = pdf_hist(pt_cold_Es, Ebins); plot!(pE, c, w; color=col_pt, lw=5)\n    for i in 1:n_pc\n        c, w = pdf_hist(pc_chain_Es[i], Ebins); plot!(pE, c, w; color=col_pc, alpha=i/n_pc, lw=2)\n    end\n    c, w = pdf_hist(pmuca_Es, Ebins); plot!(pE, c, w; color=col_muca, lw=2)\n    c, w = pdf_hist(pmuca_Es, Ebins; logw=-beta_ref .* pmuca_Es .- lw_muca.(pmuca_Es))\n    plot!(pE, c, w; color=col_muca, lw=5)\n    c, w = pdf_hist(E.(xs_exact), Ebins; logw=-beta_ref .* E.(xs_exact))\n    plot!(pE, c, w; color=col_true, lw=2)\n\n    yaxis!(px, :log10); ylims!(px, (1e-5, Inf)); xlims!(pE, (-3,3))\n    yaxis!(pE, :log10); ylims!(pE, (1e-5, Inf)); xlims!(pE, (0,2))\n\n    pl = plot(; framestyle=:none, legend=:inside,\n              foreground_color_legend=nothing, background_color_legend=nothing)\n    for (lab, col, lw, ls) in [\n        (\"True\", col_true, 5, :solid),\n        (\"Parallel Tempering\", col_pt, 5, :solid),\n        (\"Independent chains\", col_pc, 2, :solid),\n        (\"Multicanonical\", col_muca, 2, :solid),\n        (\"Muca (reweighted)\", col_muca, 2, :dash)]\n        plot!(pl, Float64[], Float64[]; label=lab, color=col, lw=lw, ls=ls)\n    end\n\n    return plot(px, pl, pE; layout=grid(1, 3, widths=[0.45, 0.1, 0.45]),\n                size=(1100, 380), margins=5Plots.mm)\nend\n\nidx_cold = findmin(abs.(betas_pt .- beta_ref))[2]\np = make_comparison_plot(;\n    pt_cold_xs  = pt_xs[idx_cold, :],\n    pt_cold_Es  = pt_Es[idx_cold, :],\n    pc_chain_xs = [pc_xs[i, :] for i in 1:size(pc)],\n    pc_chain_Es = [pc_Es[i, :] for i in 1:size(pc)],\n    pmuca_xs    = pmuca_xs,\n    pmuca_Es    = pmuca_Es,\n    lw_muca     = logweight(algorithm(pmuca, 1)),\n    beta_ref    = beta_ref,\n    xbins       = xbins,\n    Ebins       = Ebins)\n\nsavefig(p, \"parallel_chains_threads.png\")\n\n\n\nThis page was generated using Literate.jl.","title":"Comparison plot"},{"category":"section","location":"systems/#Systems-and-Model-Packages","page":"Systems","text":"MonteCarloX keeps systems external on purpose. The framework provides algorithms; companion packages provide concrete models.","title":"Systems and Model Packages"},{"category":"section","location":"systems/#Why-this-split-helps","page":"Systems","text":"algorithm implementations stay generic\nmodel packages can evolve independently\nthe same sampler can be reused across many domains","title":"Why this split helps"},{"category":"section","location":"systems/#Example:-SpinSystems-with-Ising","page":"Systems","text":"using Random\nusing MonteCarloX\nusing SpinSystems\n\nrng = MersenneTwister(123)\nsys = Ising([16, 16], J=1.0, periodic=true)\ninit!(sys, :random, rng=rng)\nalg = Metropolis(rng; β=0.44)\n\nfor _ in 1:100_000\n    spin_flip!(sys, alg)\nend\n\nprintln(\"E  = \", energy(sys))\nprintln(\"|M| = \", magnetization(sys))","title":"Example: SpinSystems with Ising"},{"category":"section","location":"systems/#What-a-custom-model-package-should-implement","page":"Systems","text":"At minimum:\n\na concrete system type (AbstractSystem subtype)\nobservable functions for analysis\nupdate methods that call MonteCarloX primitives (accept!, etc.)\ninitialization utilities (init! pattern)\n\nThis is usually enough to plug your model into measurement and algorithm workflows immediately.","title":"What a custom model package should implement"},{"category":"section","location":"generated/checkpoint_Ising2D/#Checkpoint-And-Restart-For-The-2D-Ising-Model","page":"Checkpoint And Restart For The 2D Ising Model","text":"This example shows a minimal, practical checkpoint workflow:\n\nrun Metropolis sweeps and write one rolling checkpoint file,\nsimulate an interruption,\nrestore from the checkpoint and continue,\nremove the checkpoint file after successful completion.\n\nusing Random\nusing MonteCarloX, SpinSystems\n\nconst CI_MODE = get(ENV, \"MCX_SMOKE\", get(ENV, \"MCX_CI\", \"false\")) == \"true\"\n\n","title":"Checkpoint And Restart For The 2D Ising Model"},{"category":"section","location":"generated/checkpoint_Ising2D/#Simulation-setup","page":"Checkpoint And Restart For The 2D Ising Model","text":"L = 16\nbeta = 0.44\ntotal_sweeps = CI_MODE ? 120 : 5_000\ncheckpoint_interval = CI_MODE ? 20 : 500\nreport_interval = CI_MODE ? 20 : 500\ninterrupt_after = CI_MODE ? 60 : 2_500\n\nPersistent checkpoint location. On HPC, set MCXCHECKPOINTBASE to a shared filesystem path (for example under SCRATCH) so restart works on any node.\n\ncheckpoint_base = get(\n    ENV,\n    \"MCX_CHECKPOINT_BASE\",\n    joinpath(pwd(), \"checkpoints\", \"ising2d\", \"ckpt\"),\n)\ncheckpoint_file = checkpoint_base * \".mcx\"\n\nsys = Ising([L, L])\nalg = Metropolis(Xoshiro(2026); β=beta)\nckpt = init_checkpoint(checkpoint_file, (sys=sys, alg=alg, sweep=0))\n\nfunction run_sweeps!(sys, alg, sweep_start::Int, sweep_stop::Int;\n                     ckpt::CheckpointSession,\n                     checkpoint_interval::Int,\n                     report_interval::Int)\n    for sweep in sweep_start:sweep_stop\n        for _ in 1:length(sys.spins)\n            spin_flip!(sys, alg)\n        end\n\n        if sweep % checkpoint_interval == 0\n            checkpoint!(ckpt; sweep=sweep)\n        end\n\n        if sweep % report_interval == 0 || sweep == sweep_stop\n            println(\"sweep=$(sweep), E=$(energy(sys)), M=$(magnetization(sys)), accepted=$(alg.accepted)\")\n        end\n    end\n    return nothing\nend\n\n","title":"Simulation setup"},{"category":"section","location":"generated/checkpoint_Ising2D/#Loop-1:-run-and-create-checkpoints-(simulated-preemption)","page":"Checkpoint And Restart For The 2D Ising Model","text":"init!(sys, :random, rng=Xoshiro(2026))\nprintln(\"Phase 1: running until simulated interruption at sweep $(interrupt_after)\")\nrun_sweeps!(\n    sys,\n    alg,\n    1,\n    interrupt_after;\n    ckpt=ckpt,\n    checkpoint_interval=checkpoint_interval,\n    report_interval=report_interval,\n)\n\nif !isfile(checkpoint_file)\n    throw(ArgumentError(\n        \"No checkpoint file found at $(checkpoint_file). \" *\n        \"Choose checkpoint_interval <= interrupt_after.\"))\nend\n\n","title":"Loop 1: run and create checkpoints (simulated preemption)"},{"category":"section","location":"generated/checkpoint_Ising2D/#Loop-2:-restore-and-continue","page":"Checkpoint And Restart For The 2D Ising Model","text":"println(\"Phase 2: restoring and continuing to sweep $(total_sweeps)\")\nckpt = restore_checkpoint(checkpoint_file)\nsys = ckpt.sys\nalg = ckpt.alg\nstart_sweep = ckpt.sweep + 1\n\nif start_sweep <= total_sweeps\n    run_sweeps!(\n        sys,\n        alg,\n        start_sweep,\n        total_sweeps;\n        ckpt=ckpt,\n        checkpoint_interval=checkpoint_interval,\n        report_interval=report_interval,\n    )\nend\n\nSimulation finished successfully, checkpoint no longer needed.\n\nfinalize!(ckpt)\n\nprintln(\"Finished at sweep=$(alg.steps), final energy=$(energy(sys))\")\nprintln(\"Checkpoint file removed: $(checkpoint_file)\")\n\n\n\nThis page was generated using Literate.jl.","title":"Loop 2: restore and continue"},{"category":"section","location":"generated/checkpointing_threads/#Checkpointing-with-Parallel-Chains-(Threads)","page":"Checkpointing with Parallel Chains (Threads)","text":"Demonstrate checkpoint/restore for a multi-chain simulation using threads. Since all threads share the same memory space, we can checkpoint the entire simulation state in one call. We verify that a run interrupted at a checkpoint and then continued produces identical results to an uninterrupted reference.\n\nLaunch with:\n\njulia --threads=4 --project docs/src/examples/infrastructure/checkpointing_threads.jl\n\nFor the MPI version, see checkpointing_mpi.jl.\n\nusing Random, Test\nusing MonteCarloX","title":"Checkpointing with Parallel Chains (Threads)"},{"category":"section","location":"generated/checkpointing_threads/#System-definition","page":"Checkpointing with Parallel Chains (Threads)","text":"mutable struct System\n    x::Float64\nend\n\nE(sys::System) = 1/4*(sys.x^2 - 2)^2\n\nfunction update!(sys::System, alg::AbstractImportanceSampling; delta=0.1)\n    x_new = sys.x + delta * randn(alg.rng)\n    accept!(alg, E(System(x_new)), E(sys)) && (sys.x = x_new)\nend","title":"System definition"},{"category":"section","location":"generated/checkpointing_threads/#Parameters","page":"Checkpointing with Parallel Chains (Threads)","text":"const CI_MODE = get(ENV, \"MCX_SMOKE\", get(ENV, \"MCX_CI\", \"false\")) == \"true\"\n\nn_total = CI_MODE ? 100 : 1000\nn_sweep = 10\nn_half  = n_total ÷ 2\n\nseed = 42\nβ    = 2.0\n\nbackend = ThreadsBackend()","title":"Parameters"},{"category":"section","location":"generated/checkpointing_threads/#Checkpoint-directory","page":"Checkpointing with Parallel Chains (Threads)","text":"On HPC, set MCX_RUN_DIR to a job-specific path (e.g. containing SLURM_JOB_ID).  Falls back to a temporary directory.\n\nrun_dir   = get(ENV, \"MCX_RUN_DIR\", mktempdir())\nckpt_file = joinpath(run_dir, \"ckpt.mcx\")\nprint(\"Checkpoint file: $(ckpt_file)\\n\")","title":"Checkpoint directory"},{"category":"section","location":"generated/checkpointing_threads/#Reference-run-(uninterrupted)","page":"Checkpointing with Parallel Chains (Threads)","text":"ref_algs = [Metropolis(Xoshiro(seed + i); β=β) for i in 1:size(backend)]\nref_pc   = ParallelChains(backend, ref_algs)\nref_sys  = [System(0.0) for _ in 1:size(backend)]\nref_xs   = zeros(Float64, size(backend), n_total)\n\nwith_parallel(ref_pc) do i, alg\n    sys = ref_sys[i]\n    for j in 1:n_total\n        for _ in 1:n_sweep; update!(sys, alg); end\n        ref_xs[i, j] = sys.x\n    end\nend\n\nprintln(\"Reference run: $(size(backend)) chains × $(n_total) samples\")","title":"Reference run (uninterrupted)"},{"category":"section","location":"generated/checkpointing_threads/#Checkpointed-run","page":"Checkpointing with Parallel Chains (Threads)","text":"With threads, all chains live in shared memory.  We checkpoint the full ParallelChains object and the vector of systems in one call.","title":"Checkpointed run"},{"category":"section","location":"generated/checkpointing_threads/#First-half","page":"Checkpointing with Parallel Chains (Threads)","text":"algs = [Metropolis(Xoshiro(seed + i); β=β) for i in 1:size(backend)]\npc   = ParallelChains(backend, algs)\nsys  = [System(0.0) for _ in 1:size(backend)]\n\nckpt    = init_checkpoint(ckpt_file, (sys=sys, pc=pc, sample=0))\nckpt_xs = zeros(Float64, size(backend), n_total)\n\nwith_parallel(pc) do i, alg\n    s = sys[i]\n    for j in 1:n_half\n        for _ in 1:n_sweep; update!(s, alg); end\n        ckpt_xs[i, j] = s.x\n    end\nend\n\ncheckpoint!(ckpt; sample=n_half)\nprintln(\"Checkpoint written at sample $(n_half)\")\n\n@assert ckpt_xs[:, 1:n_half] == ref_xs[:, 1:n_half] \"First half must match reference\"","title":"First half"},{"category":"section","location":"generated/checkpointing_threads/#Destroy-and-restore","page":"Checkpointing with Parallel Chains (Threads)","text":"ckpt  = restore_checkpoint(ckpt_file)\npc    = ckpt.pc\nsys   = ckpt.sys\nstart = ckpt.sample + 1\n\nprintln(\"Restored from checkpoint: sample=$(ckpt.sample)\")","title":"Destroy and restore"},{"category":"section","location":"generated/checkpointing_threads/#Second-half","page":"Checkpointing with Parallel Chains (Threads)","text":"with_parallel(pc) do i, alg\n    s = sys[i]\n    for j in start:n_total\n        for _ in 1:n_sweep; update!(s, alg); end\n        ckpt_xs[i, j] = s.x\n    end\nend\n\nfinalize!(ckpt)\nprintln(\"Resumed run complete: $(size(backend)) chains × $(n_total) samples\")","title":"Second half"},{"category":"section","location":"generated/checkpointing_threads/#Verify-identical-trajectories","page":"Checkpointing with Parallel Chains (Threads)","text":"@assert ckpt_xs == ref_xs \"Checkpointed run must exactly match reference run\"\nprintln(\"✓ Checkpointed trajectory is identical to uninterrupted reference.\")\n\n\n\nThis page was generated using Literate.jl.","title":"Verify identical trajectories"},{"category":"section","location":"checkpointing/#Checkpointing","page":"Checkpointing","text":"Long-running simulations — especially on HPC clusters with job time limits — need to save their state and resume after an interruption.\n\nMonteCarloX provides a simple checkpoint API based on Julia's Serialization. A CheckpointSession tracks a file path and a set of linked objects that are serialized together on every checkpoint! call.\n\nCheckpointing distinguishes between linked objects passed as named tuples upon init  (tracked throughout) and meta data provided at each checkpoint added as kwargs. ","title":"Checkpointing"},{"category":"section","location":"checkpointing/#Lifecycle","page":"Checkpointing","text":"using MonteCarloX\n\n# 1. Create session — writes an initial checkpoint \nckpt = init_checkpoint(\"ckpt.mcx\", (sys=sys, alg=alg), sweep=0)\n\n# 2. Inside the loop — write rolling checkpoints\ncheckpoint!(ckpt; sweep=sweep)\n\n# 3. On restart — restore state\nstate = restore_checkpoint(\"run/ckpt.mcx\")\nstart_sweep = state.sweep\n\n# 4. After successful completion — clean up\nfinalize!(ckpt)\n\nThe checkpoint file is written atomically (tmp + rename) so a crash during write never corrupts the previous checkpoint.","title":"Lifecycle"},{"category":"section","location":"checkpointing/#Single-chain-example","page":"Checkpointing","text":"using Random, Test\nusing MonteCarloX\n\n# Define system\nmutable struct System\n    x::Float64\nend\nE(sys::System) = 1/4*(sys.x^2 - 2)^2\n\nfunction update!(sys::System, alg::AbstractImportanceSampling; delta=0.1)\n    x_new = sys.x + delta * randn(alg.rng)\n    accept!(alg, E(System(x_new)), E(sys)) && (sys.x = x_new)\nend\n\n# Parameters\nn_total = 1000\nn_sweep = 10\nn_half  = n_total ÷ 2\nseed    = 42\nβ       = 2.0\n\n# Run first half\nsys = System(0.0)\nalg = Metropolis(Xoshiro(seed); β=β)\nckpt = init_checkpoint(\"ckpt.mcx\", (sys=sys, alg=alg, sample=0))\n\nfor j in 1:n_half\n    for _ in 1:n_sweep; update!(sys, alg); end\nend\n\ncheckpoint!(ckpt; sample=n_half)\n\n# Restore and continue\nckpt  = restore_checkpoint(\"ckpt.mcx\")\nsys   = ckpt.sys\nalg   = ckpt.alg\nstart = ckpt.sample + 1\n\nfor j in start:n_total\n    for _ in 1:n_sweep; update!(sys, alg); end\nend\n\nfinalize!(ckpt)","title":"Single-chain example"},{"category":"section","location":"checkpointing/#Parallel-chains-with-threads","page":"Checkpointing","text":"With thread-based parallelization, all chains share memory, so you can checkpoint the entire ParallelChains state plus system vector in one call:\n\nusing Random, MonteCarloX\n\nbackend = ThreadsBackend()\nalgs    = [Metropolis(Xoshiro(42 + i); β=2.0) for i in 1:size(backend)]\npc      = ParallelChains(backend, algs)\nsys     = [System(0.0) for _ in 1:size(backend)]\n\n# Create checkpoint session\nckpt = init_checkpoint(\"ckpt.mcx\", (sys=sys, pc=pc, sample=0))\n\n# Inside simulation loop\ncheckpoint!(ckpt; sample=0)\n\n# On restart\nckpt  = restore_checkpoint(\"ckpt.mcx\")\npc    = ckpt.pc\nsys   = ckpt.sys\nstart = ckpt.sample + 1\n\nfinalize!(ckpt)","title":"Parallel chains with threads"},{"category":"section","location":"checkpointing/#Parallel-chains-with-MPI","page":"Checkpointing","text":"Each MPI rank writes its own checkpoint file. The ParallelChains object must be reconstructed from a fresh backend on restore (MPI communicators are not serializable):\n\nusing Random, MonteCarloX, MPI\n\nbackend = init(:MPI)\nalg     = Metropolis(Xoshiro(42 + rank(backend)); β=2.0)\npc      = ParallelChains(backend, alg)\nsys     = System(0.0)\n\n# Each rank writes its own file\nckpt_file = joinpath(\"./\", \"ckpt_rank$(rank(backend)).mcx\")\nckpt = init_checkpoint(ckpt_file, (sys=sys, alg=alg, sample=0))\n\n# Restore on restart\nckpt  = restore_checkpoint(ckpt_file)\nsys   = ckpt.sys\nalg   = ckpt.alg\npc    = ParallelChains(backend, alg)  # reconstruct from existing backend\nstart = ckpt.sample + 1\n\nfinalize!(ckpt)","title":"Parallel chains with MPI"},{"category":"section","location":"checkpointing/#HPC-checkpoint-directory","page":"Checkpointing","text":"Set MCX_RUN_DIR to a job-specific path (e.g. containing SLURM_JOB_ID):\n\nrun_dir   = get(ENV, \"MCX_RUN_DIR\", mktempdir())\nckpt_file = joinpath(run_dir, \"ckpt.mcx\")","title":"HPC checkpoint directory"},{"category":"section","location":"checkpointing/#API-reference","page":"Checkpointing","text":"","title":"API reference"},{"category":"type","location":"checkpointing/#MonteCarloX.CheckpointSession","page":"Checkpointing","text":"CheckpointSession\n\nHolds the checkpoint file path and a NamedTuple of objects that will be serialized on every checkpoint! call.\n\nFields are accessed directly on the session object:\n\nckpt = restore_checkpoint(\"run/ckpt.mcx\")\nckpt.sys          # restored system\nckpt.alg          # restored algorithm\nckpt.sweep        # metadata counter\nckpt.file         # checkpoint file path (reserved)\n\nKeyword arguments passed to checkpoint! override same-named fields, allowing progress counters (e.g. sweep) to be updated without mutating the stored tuple.\n\n\n\n\n\n","title":"MonteCarloX.CheckpointSession"},{"category":"function","location":"checkpointing/#MonteCarloX.init_checkpoint","page":"Checkpointing","text":"init_checkpoint(file::String, state::NamedTuple; kwargs...)\n\nCreate a CheckpointSession, ensure the parent directory exists, and write an initial checkpoint.  Any keyword arguments (e.g. sweep=0) override same-named fields in state for the initial snapshot.\n\nExample\n\nckpt = init_checkpoint(\"run/ckpt.mcx\", (sys=sys, alg=alg, sweep=0))\n\n\n\n\n\n","title":"MonteCarloX.init_checkpoint"},{"category":"function","location":"checkpointing/#MonteCarloX.checkpoint!","page":"Checkpointing","text":"checkpoint!(ckpt::CheckpointSession; kwargs...)\n\nSerialize the stored objects to the checkpoint file.  Keyword arguments override same-named fields (e.g. sweep=100 updates the stored sweep counter).  Uses atomic write (tmp + mv) to avoid corruption.\n\n\n\n\n\n","title":"MonteCarloX.checkpoint!"},{"category":"function","location":"checkpointing/#MonteCarloX.restore_checkpoint","page":"Checkpointing","text":"restore_checkpoint(path::String) -> CheckpointSession\n\nDeserialize a checkpoint file and return a new CheckpointSession. Access restored fields directly on the returned object.\n\nExample\n\nckpt  = restore_checkpoint(\"run/ckpt.mcx\")\nsys   = ckpt.sys\nalg   = ckpt.alg\nstart = ckpt.sweep + 1\n\n\n\n\n\n","title":"MonteCarloX.restore_checkpoint"},{"category":"function","location":"checkpointing/#MonteCarloX.finalize!","page":"Checkpointing","text":"finalize!(backend)\n\nTear down the communication layer. Safe to call multiple times.\n\n\n\n\n\nfinalize!(ckpt::CheckpointSession)\n\nRemove the checkpoint file.  Call this after a simulation completes successfully so the checkpoint does not linger.\n\n\n\n\n\n","title":"MonteCarloX.finalize!"},{"category":"section","location":"generated/kmc_poisson/#Poisson-Processes-via-Kinetic-Monte-Carlo","page":"Gillespie: Poisson Process","text":"A Poisson process is the simplest continuous-time stochastic process: events occur independently at a given rate. This example builds homogeneous and inhomogeneous Poisson processes directly from the MonteCarloX.jl kinetic Monte Carlo primitives, showing both the high-level step! interface and the low-level next_time / next_event building blocks.\n\nusing Random, StatsBase, BenchmarkTools, Plots\nusing MonteCarloX","title":"Poisson Processes via Kinetic Monte Carlo"},{"category":"section","location":"generated/kmc_poisson/#Homogeneous-Poisson-process","page":"Gillespie: Poisson Process","text":"A constant rate lambda gives exponentially distributed inter-arrival times with mean 1lambda. We model this as a single-channel KMC process and validate the inter-arrival statistics.\n\nλ = 1.2\nT = 10.0\n\nalg = Gillespie(MersenneTwister(7))\narrivals = Float64[]\n\nwhile alg.time < T\n    t_new, event = step!(alg, [λ])\n    push!(arrivals, t_new)\nend\n\ninter_arrival = diff([0.0; arrivals])\nprintln(\"Events          : \", alg.steps)\nprintln(\"Mean inter-arrival — simulation : \", round(mean(inter_arrival); digits=3))\nprintln(\"Mean inter-arrival — exact      : \", round(1/λ;                 digits=3))","title":"Homogeneous Poisson process"},{"category":"section","location":"generated/kmc_poisson/#Benchmark:-step!-vs-raw-randexp","page":"Gillespie: Poisson Process","text":"The step! interface adds minimal overhead over a bare exponential draw. We compare both to quantify the cost of the KMC bookkeeping.\n\nprintln(\"\\nBenchmark: step! interface\")\n@btime begin\n    alg = Gillespie(MersenneTwister(7))\n    arr = Float64[]\n    while alg.time < $T\n        t_new, _ = step!(alg, [$λ])\n        push!(arr, t_new)\n    end\nend\n\nprintln(\"Benchmark: raw randexp\")\n@btime begin\n    rng = MersenneTwister(7)\n    t   = 0.0\n    arr = Float64[]\n    while t < $T\n        t += randexp(rng) / $λ\n        push!(arr, t)\n    end\nend","title":"Benchmark: step! vs raw randexp"},{"category":"section","location":"generated/kmc_poisson/#Inhomogeneous-Poisson-process-via-thinning","page":"Gillespie: Poisson Process","text":"When the rate varies with time, exact sampling uses thinning (Lewis & Shedler 1979): propose candidate times from a dominating homogeneous process at rate lambda_textmax, then accept each candidate with probability  lambda(t)  lambda_textmax. MonteCarloX.jl implements this internally when step! receives a Function as its event source — the function is called as rates(t) at the proposed time to evaluate acceptance.\n\nHere we have two channels with sinusoidal rates:\n\nlambda_1(t) = 06 + 03sin(t) qquad lambda_2(t) = 07 + 02cos(t)\n\nrate_fn(t)       = [0.6 + 0.3*sin(t),  0.7 + 0.2*cos(t)]\nrate_max         = [1.0, 1.0]           ## dominating rates per channel\n\nalg    = Gillespie(MersenneTwister(21))\nT      = 20.0\ncounts = zeros(Int, 2)\nevent_times = Float64[]\n\nwhile alg.time < T\n    t_new, event = step!(alg, rate_fn)\n    isnothing(event) && break\n    counts[event] += 1\n    push!(event_times, t_new)\nend\n\nprintln(\"Total events    : \", alg.steps)\nprintln(\"Channel counts  : \", counts)\nprintln(\"Final time      : \", round(alg.time; digits=3))","title":"Inhomogeneous Poisson process via thinning"},{"category":"section","location":"generated/kmc_poisson/#Visualisation","page":"Gillespie: Poisson Process","text":"The event time series shows the two channels interleaved. # The marginal inter-arrival distribution should be approximately exponential with a rate equal to the time-averaged total rate.\n\n# inter-arrival histogram vs exponential fit\nmean_rate   = mean(sum(rate_fn(t)) for t in event_times)\ninter_inhom = diff([0.0; event_times])\n\np1 = histogram(inter_inhom; bins=30, normalize=:pdf, alpha=0.6,\n               label=\"Inter-arrival\", xlabel=\"Δt\", ylabel=\"Density\",\n               title=\"Inhomogeneous inter-arrivals\")\nts = range(0, maximum(inter_inhom); length=200)\nplot!(p1, ts, mean_rate .* exp.(-mean_rate .* ts);\n      lw=2, color=:black, ls=:dash, label=\"Exp(mean rate)\")\n\nt_grid = range(0, T; length=300)\np2 = plot(t_grid, [r[1] for r in rate_fn.(t_grid)]; lw=2, label=\"λ₁(t)\",\n          xlabel=\"Time\", ylabel=\"Rate\", title=\"Time-varying rates\")\nplot!(p2, t_grid, [r[2] for r in rate_fn.(t_grid)]; lw=2, label=\"λ₂(t)\")\nvline!(p2, event_times[findall(x -> x == 1, counts)]; alpha=0.15, color=:gray, label=\"\")\n\nplot(p1, p2; layout=(1,2), size=(900, 280), margin=5Plots.mm)\n\n\n\nThis page was generated using Literate.jl.","title":"Visualisation"},{"category":"section","location":"generated/muca_Ising2D/#Multicanonical-sampling-of-the-2D-Ising-model","page":"Multicanonical sampling: Ising 2D","text":"Multicanonical (muca) sampling iteratively refines energy weights to produce a flat histogram, enabling efficient sampling across the phase transition. We validate against the exact density of states by Beale (1996).\n\nusing Random, StatsBase, Plots\nusing MonteCarloX, SpinSystems","title":"Multicanonical sampling of the 2D Ising model"},{"category":"section","location":"generated/muca_Ising2D/#Parameters","page":"Multicanonical sampling: Ising 2D","text":"const CI_MODE = get(ENV, \"MCX_SMOKE\", get(ENV, \"MCX_CI\", \"false\")) == \"true\"\n\nL             = 8;\nn_iter        = CI_MODE ? 3 : 10;\nsweeps_therm  = CI_MODE ? 100 : 1_000;\nsweeps_record = CI_MODE ? 1_000 : 100_000;\nnothing #hide","title":"Parameters"},{"category":"section","location":"generated/muca_Ising2D/#Validation-and-visualization","page":"Multicanonical sampling: Ising 2D","text":"The exact log-density of states for the Ltimes L Ising model (Beale 1996) serves as reference. rmse_exact quantifies convergence per iteration and plot_muca visualizes the histogram, estimated log-DOS against the exact reference, and the RMSE convergence.\n\nexact_logdos          = logdos_exact_ising2D(L)\nexact_logdos.values .-= exact_logdos[0]\nmask                  = .!isnan.(exact_logdos.values)\n\nfunction rmse_exact(lw)\n    est = -deepcopy(lw.values) .+ lw[0]\n    return sqrt(mean((est[mask] .- exact_logdos.values[mask]).^2))\nend\n\nfunction plot_muca(hists::Vector{BinnedObject}, lws::Vector{BinnedObject}; title=\"\")\n    n        = length(hists)\n    cols     = palette(:viridis, max(n, 2))[1:n]\n    energies = get_centers(hists[1])\n    i0       = findfirst(==(0), energies)\n\n    p1 = plot(xlabel=\"E\", ylabel=\"counts\", title=\"$(title) histograms\", legend=false)\n    for i in 1:n\n        plot!(p1, energies, hists[i].values; lw=2, color=cols[i])\n    end\n\n    p2 = plot(xlabel=\"E\", ylabel=\"-log w(E)\", title=\"$(title) log-DOS\", legend=false)\n    for i in 1:n\n        w = -deepcopy(lws[i].values)\n        i0 !== nothing && (w .-= w[i0])\n        plot!(p2, energies, w; lw=2, color=cols[i])\n    end\n    ref = Float64.(exact_logdos.values)\n    i0 !== nothing && isfinite(ref[i0]) && (ref .-= ref[i0])\n    plot!(p2, energies, ref; lw=2, color=:black, label=\"exact\")\n\n    rmse = rmse_exact.(lws)\n    p3   = scatter(1:n, rmse; ms=4, color=:steelblue,\n                   xlabel=\"iter\", ylabel=\"RMSE\",\n                   title=\"$(title) convergence\",\n                   legend=false, yscale=:log10)\n\n    return plot(p1, p2, p3; layout=(1,3), size=(980,260), margin=4Plots.mm), rmse\nend","title":"Validation and visualization"},{"category":"section","location":"generated/muca_Ising2D/#Serial-MUCA","page":"Multicanonical sampling: Ising 2D","text":"A single Markov chain accumulates the energy histogram.\n\nsys = Ising([L, L])\ninit!(sys, :random, rng=Xoshiro(1000))\nalg = Multicanonical(Xoshiro(1000), get_centers(exact_logdos))\n\nserial_hists, serial_lws = BinnedObject[], BinnedObject[]\nfor _ in 1:n_iter\n    for _ in 1:(sweeps_therm  * length(sys.spins))\n        spin_flip!(sys, alg)\n    end\n    reset!(alg)\n    for _ in 1:(sweeps_record * length(sys.spins))\n        ;spin_flip!(sys, alg)\n    end\n    update!(ensemble(alg); mode=:simple)\n    push!(serial_hists, deepcopy(alg.ensemble.histogram))\n    push!(serial_lws,   deepcopy(alg.ensemble.logweight))\nend\n\nplt, rmse = plot_muca(serial_hists, serial_lws; title=\"Serial\")\nprintln(\"Serial RMSE = \", round(last(rmse), digits=4))\ndisplay(plt)","title":"Serial MUCA"},{"category":"section","location":"generated/muca_Ising2D/#Production-runs","page":"Multicanonical sampling: Ising 2D","text":"For parallel multicanonical with MPI, see the standalone script:\n\nmpiexec -n 4 julia --project=docs \\\n    docs/src/examples/spin_systems/muca_Ising2D_mpi.jl\n\nFor parallel multicanonical with threads, see:\n\njulia --threads=4 --project docs/src/examples/infrastructure/parallel_chains_threads.jl\n\n\n\nThis page was generated using Literate.jl.","title":"Production runs"},{"category":"section","location":"generated/muca_sum_gaussian/#Large-Deviation-Theory:-Sum-of-Gaussian-Random-Variables","page":"Multicanonical: Sum of Gaussians","text":"Large deviation theory (LDT) describes the probability of observing rare, atypical fluctuations of macroscopic observables far from their mean. For a sum S_N = sum_i=1^N X_i of i.i.d. random variables, the central limit theorem governs typical fluctuations, but LDT governs the exponentially rare tails.\n\nThis example uses the sum of N Gaussian random variables as a tractable benchmark — the exact distribution is known analytically — and demonstrates three sampling strategies:\n\nDirect sampling — reference\nImportance sampling via Metropolis with a biasing field beta\nMulticanonical sampling — flat histogram across the full distribution\n\nusing Random, Distributions\nusing StatsBase, LinearAlgebra\nusing MonteCarloX\nusing Plots, ProgressMeter","title":"Large Deviation Theory: Sum of Gaussian Random Variables"},{"category":"section","location":"generated/muca_sum_gaussian/#CI-parameters","page":"Multicanonical: Sum of Gaussians","text":"const CI_MODE = get(ENV, \"MCX_SMOKE\", get(ENV, \"MCX_CI\", \"false\")) == \"true\"\n\nn_direct   = CI_MODE ? 1_000   : 100_000\nn_therm    = CI_MODE ? 100     : 10_000\nn_metro    = CI_MODE ? 1_000   : 1_000_000\nn_muca     = CI_MODE ? 1_000   : 10_000_000\nn_muca_known = CI_MODE ? 1_000 : 50_000_000\nn_iter     = CI_MODE ? 3       : 10\nn_iter_steps = CI_MODE ? 1_000 : 5_000_000","title":"CI parameters"},{"category":"section","location":"generated/muca_sum_gaussian/#Parameters","page":"Multicanonical: Sum of Gaussians","text":"μ, σ, N = 0.0, 1.0, 100\n\n# exact distribution of S_N is Normal(N*μ, sqrt(N)*σ)\npdf_sum     = Normal(N*μ, sqrt(N)*σ)\nstd_sum     = sqrt(N)*σ\nbins_sum    = (N*μ - 10*std_sum) : (std_sum/10) : (N*μ + 10*std_sum)\ncenters_sum = collect(bins_sum[1:end-1] .+ diff(collect(bins_sum))./2)\nlogpdf_sum  = logpdf.(pdf_sum, centers_sum)","title":"Parameters"},{"category":"section","location":"generated/muca_sum_gaussian/#System-definition","page":"Multicanonical: Sum of Gaussians","text":"The system state is a vector of N Gaussian random variables together with their running sum. Only the sum enters the sampling weight; the individual variables evolve under their own Gaussian prior via a Metropolis-within-Gibbs step.\n\nmutable struct SumGaussianRVs\n    logpdf_rv :: Function\n    rvs       :: Vector{Float64}\n    sum_rvs   :: Float64\n    function SumGaussianRVs(rng, N; μ=0.0, σ=1.0)\n        dist = Normal(μ, σ)\n        rvs  = rand(rng, dist, N)\n        new(x -> logpdf(dist, x), rvs, sum(rvs))\n    end\nend\n\nsum_rvs(sys::SumGaussianRVs) = sys.sum_rvs\n\nEach update proposes a move for one randomly chosen variable. The proposal is first filtered by the Gaussian prior (Metropolis-within-Gibbs), then accepted by the sampling algorithm based on the sum.\n\nfunction update!(sys::SumGaussianRVs, alg::AbstractImportanceSampling; δ=0.5)\n    idx    = rand(alg.rng, 1:length(sys.rvs))\n    rv_old = sys.rvs[idx]\n    rv_new = rv_old + δ * (2*rand(alg.rng) - 1)\n    if rand(alg.rng) < exp(sys.logpdf_rv(rv_new) - sys.logpdf_rv(rv_old))\n        sum_new = sys.sum_rvs + (rv_new - rv_old)\n        if accept!(alg, sum_new, sys.sum_rvs)\n            sys.sum_rvs  = sum_new\n            sys.rvs[idx] = rv_new\n        end\n    else\n        alg.steps += 1\n    end\nend","title":"System definition"},{"category":"section","location":"generated/muca_sum_gaussian/#Direct-sampling","page":"Multicanonical: Sum of Gaussians","text":"We draw independent sums as a reference distribution.\n\ndirect_samples = [sum(μ .+ σ .* randn(MersenneTwister(i), N)) for i in 1:n_direct]\nhist_direct    = normalize(fit(Histogram, direct_samples, bins_sum); mode=:pdf)\n\nplot(hist_direct; st=:bar, linewidth=0, alpha=0.6,\n     label=\"Direct samples\", xlabel=\"S_N\", ylabel=\"Density\",\n     title=\"Direct sampling vs exact\", size=(600, 250), margin=5Plots.mm)\nplot!(centers_sum, pdf.(pdf_sum, centers_sum);\n      lw=2, color=:black, ls=:dash, label=\"Exact\")","title":"Direct sampling"},{"category":"section","location":"generated/muca_sum_gaussian/#Importance-sampling-with-Metropolis","page":"Multicanonical: Sum of Gaussians","text":"A biasing field beta tilts the sampling distribution toward larger (beta  0) or smaller (beta  0) values of S_N. At beta = 0 this reduces to uniform sampling of the Gaussian.\n\nfunction run_metropolis(; β=0.0)\n    sys  = SumGaussianRVs(MersenneTwister(23), N; μ=μ, σ=σ)\n    alg  = Metropolis(MersenneTwister(42); β=β)\n    meas = Measurements([:sum => sum_rvs => fit(Histogram, [], bins_sum)], interval=1)\n    for _ in 1:n_therm;  update!(sys, alg); end\n    for i in 1:n_metro;  update!(sys, alg); measure!(meas, sys, i); end\n    println(\"β = $(β):  acceptance = \", round(acceptance_rate(alg); digits=3))\n    return meas\nend\n\nβs      = [-0.5, 0.0, 0.5]\nresults = Dict(β => run_metropolis(β=β) for β in βs)\n\np_is = plot(centers_sum, pdf.(pdf_sum, centers_sum);\n            lw=2, color=:black, ls=:dash, label=\"Exact\",\n            xlabel=\"S_N\", ylabel=\"Density\",\n            title=\"Importance sampling\", size=(600, 250), margin=5Plots.mm)\nfor β in βs\n    w    = results[β][:sum].data.weights\n    norm = sum(w) * step(bins_sum)\n    plot!(p_is, centers_sum, w ./ norm; lw=2, label=\"β = $β\")\nend\np_is","title":"Importance sampling with Metropolis"},{"category":"section","location":"generated/muca_sum_gaussian/#Multicanonical-sampling-—-flat-histogram","page":"Multicanonical: Sum of Gaussians","text":"With flat weights (w = 1) the multicanonical algorithm samples the full distribution uniformly, including the exponentially rare tails. This is equivalent to beta = 0 importance sampling but achieved without knowing the target distribution in advance.\n\nsys_muca0 = SumGaussianRVs(MersenneTwister(23), N; μ=μ, σ=σ)\nalg_muca0 = Multicanonical(MersenneTwister(100), bins_sum; init=0.0)\n\nfor _ in 1:n_therm;  update!(sys_muca0, alg_muca0); end\nreset!(alg_muca0)\nfor _ in 1:n_muca;   update!(sys_muca0, alg_muca0); end\nprintln(\"MUCA (flat):  acceptance = \", round(acceptance_rate(alg_muca0); digits=3))\n\nhist_muca0 = alg_muca0.ensemble.histogram.values\ndist_muca0 = hist_muca0 / sum(hist_muca0) / step(bins_sum)\nplot(centers_sum, dist_muca0; lw=2, label=\"MUCA (flat weights)\",\n     xlabel=\"S_N\", ylabel=\"Density\",\n     title=\"Multicanonical flat histogram\", size=(600, 250), margin=5Plots.mm)\nplot!(centers_sum, pdf.(pdf_sum, centers_sum); lw=2, color=:black, ls=:dash, label=\"Exact\")","title":"Multicanonical sampling — flat histogram"},{"category":"section","location":"generated/muca_sum_gaussian/#Multicanonical-with-known-weights","page":"Multicanonical: Sum of Gaussians","text":"If the target distribution is known, we can initialise the weights to the exact log-PDF and add linear tails to prevent the chain running away at the boundaries.\n\nsys_known = SumGaussianRVs(MersenneTwister(42), N; μ=μ, σ=σ)\nalg_known = Multicanonical(MersenneTwister(42), bins_sum)\nlw        = logweight(alg_known)\ncs        = get_centers(lw)\n\nset!(lw, (first(cs), last(cs)), x -> -logpdf(pdf_sum, x))\n\nx_left  = -3*std_sum\nx_right = +3*std_sum\nset!(lw, (first(cs), x_left),  x -> lw(x_left)  + (x - x_left)  * 2.0)\nset!(lw, (x_right,  last(cs)), x -> lw(x_right) - (x - x_right) * 2.0)\n\nplot(cs, get_values(lw); lw=2, label=\"Initialised logweight\",\n     xlabel=\"S_N\", ylabel=\"log w(S_N)\",\n     title=\"Logweight vs exact log-PDF\", size=(600, 250), margin=5Plots.mm)\nplot!(cs, -logpdf_sum; lw=2, color=:black, ls=:dash, label=\"Exact −log PDF\")\n\nfor _ in 1:n_therm;      update!(sys_known, alg_known; δ=0.1); end\nreset!(alg_known)\nfor _ in 1:n_muca_known; update!(sys_known, alg_known; δ=0.1); end\nprintln(\"MUCA (known): acceptance = \", round(acceptance_rate(alg_known); digits=3))\n\nhist_known = alg_known.ensemble.histogram.values\ndist_known = hist_known / sum(hist_known) / step(bins_sum)\nplot(centers_sum, dist_known; lw=2, label=\"MUCA (known weights)\",\n     xlabel=\"S_N\", ylabel=\"Density\",\n     title=\"MUCA with exact initialisation\", size=(600, 250), margin=5Plots.mm)\nplot!(centers_sum, pdf.(pdf_sum, centers_sum); lw=2, color=:black, ls=:dash, label=\"Exact\")","title":"Multicanonical with known weights"},{"category":"section","location":"generated/muca_sum_gaussian/#Multicanonical-iteration","page":"Multicanonical: Sum of Gaussians","text":"Starting from flat weights, the algorithm iteratively refines the log-weights until the histogram is flat across the full support. Linear boundary tails are reapplied after each iteration to prevent the chain escaping the binned region.\n\nsys_iter = SumGaussianRVs(MersenneTwister(42), N; μ=μ, σ=σ)\nalg_iter = Multicanonical(MersenneTwister(42), bins_sum)\n\niter_hists  = BinnedObject[]\niter_lws    = BinnedObject[]\niter_accept = Float64[]\n\nlw_iter  = logweight(alg_iter)\ncs_iter  = get_centers(lw_iter)\nx_left   = first(bins_sum) + std_sum\nx_right  = last(bins_sum)  - std_sum\ni_left   = searchsortedfirst(cs_iter, x_left)\ni_right  = searchsortedlast(cs_iter,  x_right)\n\n@showprogress 1 \"Iterating MUCA...\" for _ in 1:n_iter\n    for _ in 1:n_therm;      update!(sys_iter, alg_iter); end\n    reset!(alg_iter)\n    for _ in 1:n_iter_steps; update!(sys_iter, alg_iter); end\n\n    MonteCarloX.update!(ensemble(alg_iter); mode=:simple)\n\n    wl = get_values(lw_iter)[i_left]\n    wr = get_values(lw_iter)[i_right]\n    set!(lw_iter, (first(cs_iter), cs_iter[i_left]),  x -> wl + (x - cs_iter[i_left]) * 2.0)\n    set!(lw_iter, (cs_iter[i_right], last(cs_iter)),  x -> wr - (x - cs_iter[i_right]) * 2.0)\n\n    push!(iter_hists,  deepcopy(ensemble(alg_iter).histogram))\n    push!(iter_lws,    deepcopy(ensemble(alg_iter).logweight))\n    push!(iter_accept, acceptance_rate(alg_iter))\nend\n\nplot(iter_accept; xlabel=\"Iteration\", ylabel=\"Acceptance rate\",\n     title=\"Convergence of acceptance rate\", label=nothing,\n     size=(600, 220), margin=5Plots.mm)\n\nEach panel shows the evolution of the histogram (left) and the estimated log-DOS against the exact reference (right) over iterations.\n\nfunction plot_muca_convergence(hists, lws; ref_logpdf=logpdf_sum)\n    n    = length(hists)\n    cols = palette(:viridis, max(n,2))[1:n]\n    xs   = get_centers(hists[1].bins[1])\n    i0   = searchsortedlast(xs, 0.0)\n\n    p1 = plot(xlabel=\"S_N\", ylabel=\"Counts\", title=\"Histograms\", legend=false)\n    for i in 1:n\n        plot!(p1, xs, hists[i].values; lw=2, color=cols[i])\n    end\n\n    p2 = plot(xlabel=\"S_N\", ylabel=\"-log w\", title=\"Log-DOS vs exact\", legend=:topright)\n    for i in 1:n\n        w = -lws[i].values .+ lws[i].values[i0]\n        plot!(p2, xs, w; lw=2, color=cols[i], label=\"\")\n    end\n    plot!(p2, xs, ref_logpdf .- ref_logpdf[i0];\n          lw=2, color=:black, ls=:dash, label=\"Exact\")\n\n    return plot(p1, p2; layout=(1,2), size=(900, 280), margin=4Plots.mm)\nend\n\nplot_muca_convergence(iter_hists, iter_lws)","title":"Multicanonical iteration"},{"category":"section","location":"generated/muca_sum_gaussian/#Reweighting-to-a-biased-ensemble","page":"Multicanonical: Sum of Gaussians","text":"A single multicanonical run can be reweighted post-hoc to any target ensemble with biasing field beta, recovering the same result as a dedicated Metropolis run at that beta.\n\nβ_rw    = 0.5\nhist_rw = deepcopy(ensemble(alg_iter).histogram)\nfor i in eachindex(hist_rw.values)\n    c = hist_rw.bins[1].centers[i]\n    hist_rw.values[i] *= exp(-β_rw * c - iter_lws[end].values[i])\nend\nnorm_rw = sum(hist_rw.values) * step(bins_sum)\n\nw_metro = results[β_rw][:sum].data.weights\nnorm_m  = sum(w_metro) * step(bins_sum)\n\nplot(centers_sum, hist_rw.values ./ norm_rw;\n     lw=2, color=:black, label=\"MUCA reweighted β=$β_rw\",\n     xlabel=\"S_N\", ylabel=\"Density\",\n     title=\"Reweighting vs direct Metropolis\", size=(600, 250), margin=5Plots.mm)\nplot!(centers_sum, w_metro ./ norm_m;\n      lw=2, color=:steelblue, ls=:dash, label=\"Metropolis β=$β_rw\")\n\n\n\nThis page was generated using Literate.jl.","title":"Reweighting to a biased ensemble"},{"category":"section","location":"weights/#Weights","page":"Weights","text":"Weights determine relative probabilities in equilibrium workflows. Algorithms only need differences in log weight, so the representation can stay flexible.\n\nThe same callable concept also covers Bayesian targets:\n\nBayesian inference: logweight(theta) = logposterior(theta) = loglikelihood(theta) + logprior(theta)\nStatistical mechanics: logweight(x) = -beta * E(x)\n\nIn the sampler API this callable is stored as the algorithm ensemble, with logweight(alg) as an equivalent accessor.\n\nFor canonical targets,\n\npi(x) = frace^-beta E(x)Z(beta)\n\nso\n\nlog pi(x) = -beta E(x) - log Z(beta)\n\nand local acceptance decisions depend on\n\nDelta log pi = -betaDelta E","title":"Weights"},{"category":"section","location":"weights/#1)-Canonical-ensemble:-BoltzmannEnsemble","page":"Weights","text":"For energy E, the log weight is -beta E.\n\nusing Random\nusing MonteCarloX\n\nrng = MersenneTwister(1)\nalg = Metropolis(rng; β=0.5)  # internally uses BoltzmannEnsemble(β=0.5)\n\nUse this for standard fixed-temperature sampling.","title":"1) Canonical ensemble: BoltzmannEnsemble"},{"category":"section","location":"weights/#2)-Tabulated-weights:-BinnedObject","page":"Weights","text":"Use when the weight is not known analytically, or when adapting it online (multicanonical or Wang-Landau).\n\nusing MonteCarloX\n\nlw = BinnedObject(-20:2:20, 0.0)\nlw[0]   = 1.5\nvalue   = lw(0)\nlw_zero = zero(lw)\n\nBinnedObject supports discrete and continuous bin definitions, including multidimensional bin tuples.","title":"2) Tabulated weights: BinnedObject"},{"category":"section","location":"weights/#How-to-choose","page":"Weights","text":"Known canonical target: BoltzmannEnsemble\nExploratory generalized-ensemble run: BinnedObject + Multicanonical or WangLandau","title":"How to choose"},{"category":"section","location":"weights/#API-reference","page":"Weights","text":"","title":"API reference"},{"category":"type","location":"weights/#MonteCarloX.BoltzmannEnsemble","page":"Weights","text":"BoltzmannEnsemble\n\nCanonical-ensemble score with logweight(E) = -beta * E.\n\n\n\n\n\n","title":"MonteCarloX.BoltzmannEnsemble"},{"category":"type","location":"weights/#MonteCarloX.FunctionEnsemble","page":"Weights","text":"FunctionEnsemble\n\nWrap an arbitrary callable (e.g. Bayesian logdensity/logposterior function) in an ensemble object.\n\n\n\n\n\n","title":"MonteCarloX.FunctionEnsemble"},{"category":"type","location":"weights/#MonteCarloX.BinnedObject","page":"Weights","text":"BinnedObject(domain::AbstractRange, init)\n\nConstruct a binned log weight object for the given domain and initial value. The type of domain determines the specific binned log weight type:\n\nExamples\n\n# Discrete 1D\nbo1d = BinnedObject(0:10, 0.0)\n# Discrete ND\nbo2d = BinnedObject((0:5, 0:5), 0.0)\n# Continuous 1D\nbo1d_cont = BinnedObject(0.0:0.5:5.0, 0.0)\n# Continuous ND\nbo2d_cont = BinnedObject((0.0:0.5:5.0, 0.0:0.5:5.0), 0.0)\n\n\n\n\n\n","title":"MonteCarloX.BinnedObject"},{"category":"function","location":"weights/#MonteCarloX.get_centers","page":"Weights","text":"get_centers(bo::BinnedObject, dim::Int=1)\n\nReturn bin centers along dimension dim. For discrete bins this returns the bin support values.\n\n\n\n\n\n","title":"MonteCarloX.get_centers"},{"category":"method","location":"weights/#MonteCarloX.get_values-Tuple{BinnedObject}","page":"Weights","text":"get_values(bo::BinnedObject)\n\nReturn the underlying array of bin values.\n\n\n\n\n\n","title":"MonteCarloX.get_values"},{"category":"method","location":"weights/#Base.zero-Tuple{BinnedObject}","page":"Weights","text":"zero(lw::BinnedObject)\n\nReturn a new BinnedObject of the same bins as lw but with all values set to zero.\n\n\n\n\n\n","title":"Base.zero"},{"category":"section","location":"generated/gillespie_dimerization/#Reversible-Dimerization-with-Gillespie-Algorithm","page":"Gillespie: Dimerization Reaction","text":"This example demonstrates continuous-time stochastic simulation of a reversible dimerization reaction using the Gillespie algorithm:\n\nA + B undersetk_textoffstackrelk_textonrightleftharpoons AB\n\nThe Gillespie algorithm samples exact trajectories of the chemical master equation by drawing the time to the next reaction event from an exponential distribution and selecting the reaction channel proportionally to its rate.\n\nusing Random, StatsBase, Plots\nusing MonteCarloX","title":"Reversible Dimerization with Gillespie Algorithm"},{"category":"section","location":"generated/gillespie_dimerization/#System-definition","page":"Gillespie: Dimerization Reaction","text":"The system state tracks molecule counts of three species. Two reaction channels are defined: association (A + B → AB) and dissociation (AB → A + B).\n\nmutable struct ReversibleDimerModel <: AbstractSystem\n    A    :: Int\n    B    :: Int\n    AB   :: Int\n    k_on  :: Float64\n    k_off :: Float64\nend\n\n# propensities: rates at which each reaction fires\nreaction_rates(sys::ReversibleDimerModel, t) = [\n    sys.k_on  * sys.A * sys.B,   ## association\n    sys.k_off * sys.AB,           ## dissociation\n]\n\nfunction modify!(sys::ReversibleDimerModel, event::Int, t)\n    if event == 1 && sys.A > 0 && sys.B > 0\n        sys.A -= 1;  sys.B -= 1;  sys.AB += 1\n    elseif event == 2 && sys.AB > 0\n        sys.A += 1;  sys.B += 1;  sys.AB -= 1\n    end\n    return sys\nend","title":"System definition"},{"category":"section","location":"generated/gillespie_dimerization/#Parameters-and-initialisation","page":"Gillespie: Dimerization Reaction","text":"We start with 30 molecules each of A and B and no dimers. The on-rate k_texton = 001 and off-rate k_textoff = 05 set the equilibrium dimer fraction.\n\nsys = ReversibleDimerModel(30, 20, 0, 0.01, 0.5)\nalg = Gillespie(MersenneTwister(23))\nT   = 200.0\n\nprintln(\"Initial state: A=$(sys.A),  B=$(sys.B),  AB=$(sys.AB)\")\nprintln(\"k_on = $(sys.k_on),  k_off = $(sys.k_off)\")","title":"Parameters and initialisation"},{"category":"section","location":"generated/gillespie_dimerization/#Simulation","page":"Gillespie: Dimerization Reaction","text":"step! draws the next event time from the Gillespie distribution and returns the event index. Measurements are recorded before modify! so that each sample reflects the state during the inter-event interval.\n\nmeasurement_times = collect(0.0:0.5:T)\nmeasurements = Measurements([\n    :A  => (s -> s.A)  => Int[],\n    :B  => (s -> s.B)  => Int[],\n    :AB => (s -> s.AB) => Int[],\n], measurement_times)\n\nmeasure!(measurements, sys, alg.time)   ## record initial state\n\nwhile alg.time <= T\n    t_new, event = step!(alg, t -> reaction_rates(sys, t))\n    measure!(measurements, sys, t_new)  ## before modify!\n    modify!(sys, event, t_new)\nend\n\nprintln(\"Final time   : \", round(alg.time; digits=2))\nprintln(\"Final state  : A=$(sys.A),  B=$(sys.B),  AB=$(sys.AB)\")\nprintln(\"Total events : \", alg.steps)","title":"Simulation"},{"category":"section","location":"generated/gillespie_dimerization/#Trajectory","page":"Gillespie: Dimerization Reaction","text":"The system reaches a dynamic equilibrium in which molecules continuously associate and dissociate. The sum A + B + 2·AB is conserved throughout.\n\nA_t  = measurements[:A].data\nB_t  = measurements[:B].data\nAB_t = measurements[:AB].data\n\nplot(measurement_times, A_t;  lw=2, label=\"A\",\n     xlabel=\"Time\", ylabel=\"Count\",\n     title=\"Reversible dimerization trajectory\",\n     size=(700, 280), margin=5Plots.mm)\nplot!(measurement_times, B_t;  lw=2, label=\"B\")\nplot!(measurement_times, AB_t; lw=2, label=\"AB\")","title":"Trajectory"},{"category":"section","location":"generated/gillespie_dimerization/#Equilibrium-statistics","page":"Gillespie: Dimerization Reaction","text":"Time-averaged counts after the system has equilibrated. The law of mass action predicts langle AB rangle  (langle Aranglelangle Brangle) = k_textonk_textoff.\n\nt_eq  = T / 4   ## discard first quarter as transient\ni_eq  = searchsortedfirst(measurement_times, t_eq)\n\nA_eq  = mean(A_t[i_eq:end])\nB_eq  = mean(B_t[i_eq:end])\nAB_eq = mean(AB_t[i_eq:end])\n\nratio_sim   = AB_eq / (A_eq * B_eq)\nratio_exact = sys.k_on / sys.k_off\n\nprintln(\"Time-averaged counts (t > $(t_eq)):\")\nprintln(\"  ⟨A⟩  = \", round(A_eq;  digits=3))\nprintln(\"  ⟨B⟩  = \", round(B_eq;  digits=3))\nprintln(\"  ⟨AB⟩ = \", round(AB_eq; digits=3))\nprintln(\"Mass-action ratio — simulation: \", round(ratio_sim;   digits=4),\n                          \"  exact: \",      round(ratio_exact; digits=4))\n\n\n\nThis page was generated using Literate.jl.","title":"Equilibrium statistics"},{"category":"section","location":"generated/importance_Ising2D/#Importance-Sampling-of-the-2D-Ising-Model","page":"Importance sampling: Ising Model","text":"This example demonstrates importance sampling for the 2D Ising model with Hamiltonian H = -Jsum_langle ijrangle s_i s_j. We cover three topics: (1) system implementations and their runtime, (2) sampling algorithms, and (3) validation against the exact solution.\n\nusing Random, StatsBase, Plots, BenchmarkTools\nusing MonteCarloX, SpinSystems\nusing Graphs, SparseArrays","title":"Importance Sampling of the 2D Ising Model"},{"category":"section","location":"generated/importance_Ising2D/#CI-parameters","page":"Importance sampling: Ising Model","text":"const CI_MODE = get(ENV, \"MCX_SMOKE\", get(ENV, \"MCX_CI\", \"false\")) == \"true\"\n\ntherm_sweeps     = CI_MODE ? 10    : 1_000\nprod_sweeps      = CI_MODE ? 100   : 10_000\nmeasure_interval = 10","title":"CI parameters"},{"category":"section","location":"generated/importance_Ising2D/#Parameters","page":"Importance sampling: Ising Model","text":"L    = 8\nβ    = 0.3\nseed = 42","title":"Parameters"},{"category":"section","location":"generated/importance_Ising2D/#System-implementations","page":"Importance sampling: Ising Model","text":"MonteCarloX.jl provides several ways to represent the 2D Ising model, trading generality for performance:\n\nIsing([L,L]): general lattice, uses Graphs.jl under the hood\nIsing(J_matrix): general, accepts any sparse coupling matrix\nIsingLatticeOptim: hard-coded 2D square lattice with periodic boundaries\n\nWe benchmark a single spin_flip! step for each.\n\nalg_bench = Metropolis(Xoshiro(seed); β=β)\n\nsys_graph  = Ising([L, L]; J=1, periodic=true)\ninit!(sys_graph,  :random, rng=MersenneTwister(seed))\n\ngrid_graph = Graphs.SimpleGraphs.grid([L, L]; periodic=true)\nsys_matrix = Ising(SparseMatrixCSC{Float64,Int}(adjacency_matrix(grid_graph)))\ninit!(sys_matrix, :random, rng=MersenneTwister(seed))\n\nsys_optim  = IsingLatticeOptim(L, L)\ninit!(sys_optim,  :random, rng=MersenneTwister(seed))\n\nprintln(\"Graph-based Ising:\")\n@btime spin_flip!($sys_graph,  $alg_bench)\nprintln(\"Matrix-coupling Ising:\")\n@btime spin_flip!($sys_matrix, $alg_bench)\nprintln(\"Optimized 2D Ising:\")\n@btime spin_flip!($sys_optim,  $alg_bench)\n\nThe optimized implementation is significantly faster because it exploits the fixed lattice geometry to avoid graph traversal and sparse matrix lookups. The graph-based version is the most flexible — it works for any lattice geometry or connectivity without any code changes.","title":"System implementations"},{"category":"section","location":"generated/importance_Ising2D/#Custom-acceptance-rule","page":"Importance sampling: Ising Model","text":"For the 2D Ising model Delta E in -8-4048, so we can precompute the two non-trivial acceptance probabilities and avoid calling exp at every step. This shows how to extend MonteCarloX.jl with a custom algorithm by implementing the accept! interface.\n\nmutable struct TableMetropolis{R<:AbstractRNG} <: AbstractMetropolis\n    rng      :: R\n    p4       :: Float64\n    p8       :: Float64\n    steps    :: Int\n    accepted :: Int\nend\n\nTableMetropolis(rng::AbstractRNG; β::Real) =\n    TableMetropolis(rng, exp(-4β), exp(-8β), 0, 0)\n\n@inline function MonteCarloX.accept!(alg::TableMetropolis, dE::Int)\n    alg.steps += 1\n    dE <= 0 && (alg.accepted += 1; return true)\n    p        = dE == 4 ? alg.p4 : alg.p8\n    accepted = rand(alg.rng) < p\n    alg.accepted += accepted\n    return accepted\nend\n\nsys_table = IsingLatticeOptim(L, L)\ninit!(sys_table, :random, rng=Xoshiro(seed))\nalg_table = TableMetropolis(Xoshiro(seed); β=β)\n\nprintln(\"Standard Metropolis + Xoshiro:\")\n@btime spin_flip!($sys_optim, $alg_bench)\nprintln(\"TableMetropolis + Xoshiro:\")\n@btime spin_flip!($sys_table, $alg_table)","title":"Custom acceptance rule"},{"category":"section","location":"generated/importance_Ising2D/#Simulation-helper","page":"Importance sampling: Ising Model","text":"function run_chain!(sys, alg)\n    N = length(sys.spins)\n    measurements = Measurements([\n        :energy        => energy        => Float64[],\n        :magnetization => magnetization => Float64[],\n    ], interval=measure_interval)\n    for _ in 1:(N * therm_sweeps); spin_flip!(sys, alg); end\n    hasmethod(reset!, Tuple{typeof(alg)}) && reset!(alg)\n    for i in 1:(N * prod_sweeps)\n        spin_flip!(sys, alg)\n        measure!(measurements, sys, i)\n    end\n    energies = measurements[:energy].data\n    mags     = measurements[:magnetization].data\n    return (; energies, mags,\n              avg_E = mean(energies) / N,\n              avg_M = mean(abs.(mags)) / N)\nend","title":"Simulation helper"},{"category":"section","location":"generated/importance_Ising2D/#Validation-helper","page":"Importance sampling: Ising Model","text":"The exact energy distribution follows the Boltzmann weights applied to the exact density of states (Beale 1996). plot_importance_sampling overlays the sampled histograms of all algorithms against this reference.\n\nexact_logdos          = logdos_exact_ising2D(L)\nexact_logdos.values .-= exact_logdos[0]\nlog_dos  = exact_logdos.values\nlog_w    = log_dos .- β .* get_centers(exact_logdos)\nlog_Z    = reduce((a,b) -> a > b ? a + log1p(exp(b-a)) : b + log1p(exp(a-b)),\n                  filter(isfinite, log_w))\nmask     = isfinite.(log_dos)\nE_exact  = get_centers(exact_logdos)\nP_exact  = zeros(length(log_w))\nP_exact[mask] = exp.(log_w[mask] .- log_Z)\n\nfunction plot_importance_sampling(results, labels)\n    p_ts   = plot(xlabel=\"Measurement step\", ylabel=\"Energy\",\n                  title=\"Time series\", legend=:topright)\n    p_dist = plot(xlabel=\"Energy\", ylabel=\"Probability\",\n                  title=\"Distribution vs exact\", legend=:topright)\n    cols = palette(:tab10)\n    for (i, (res, label)) in enumerate(zip(results, labels))\n        plot!(p_ts, res.energies; lw=1, color=cols[i])\n        edges = get_edges(exact_logdos.bins[1])\n        hist  = fit(Histogram, res.energies, edges, closed=:left)\n        dist  = StatsBase.normalize(hist; mode=:probability)\n        plot!(p_dist, dist; label=label, lw=2, color=cols[i])\n    end\n    mask = isfinite.(P_exact)\n    plot!(p_dist, E_exact[mask], P_exact[mask];\n          label=\"Exact\", color=:black, lw=2, ls=:dash)\n    return plot(p_ts, p_dist; layout=(1,2), size=(980,320), margin=4Plots.mm)\nend","title":"Validation helper"},{"category":"section","location":"generated/importance_Ising2D/#Metropolis","page":"Importance sampling: Ising Model","text":"The Metropolis-Hastings algorithm accepts a proposed spin flip with probability min(1 e^-betaDelta E). It is the standard workhorse for spin systems: simple, general, and efficient.\n\nsys_meta = IsingLatticeOptim(L, L)\ninit!(sys_meta, :random, rng=MersenneTwister(seed))\nres_meta = run_chain!(sys_meta, Metropolis(MersenneTwister(seed); β=β))\n\nplot_importance_sampling([res_meta], [\"Metropolis\"])","title":"Metropolis"},{"category":"section","location":"generated/importance_Ising2D/#Heat-Bath","page":"Importance sampling: Ising Model","text":"The Heat Bath algorithm accepts with probability 1(1+e^betaDelta E), which corresponds to directly sampling the conditional distribution of a single spin given its neighbours. It tends to have shorter autocorrelation times than Metropolis at low temperatures.\n\nsys_hb = IsingLatticeOptim(L, L)\ninit!(sys_hb, :random, rng=MersenneTwister(seed))\nres_hb = run_chain!(sys_hb, HeatBath(MersenneTwister(seed); β=β))\n\nplot_importance_sampling([res_hb], [\"HeatBath\"])","title":"Heat Bath"},{"category":"section","location":"generated/importance_Ising2D/#Glauber","page":"Importance sampling: Ising Model","text":"The Glauber dynamics use the same acceptance probability as Heat Bath and are equivalent for spin-12 systems. The distinction matters for systems with more than two spin states, where Glauber uses a linearised transition rate rather than the exact conditional distribution.\n\nsys_gla = IsingLatticeOptim(L, L)\ninit!(sys_gla, :random, rng=MersenneTwister(seed))\nres_gla = run_chain!(sys_gla, Glauber(MersenneTwister(seed); β=β))\n\nplot_importance_sampling([res_gla], [\"Glauber\"])","title":"Glauber"},{"category":"section","location":"generated/importance_Ising2D/#Comparison","page":"Importance sampling: Ising Model","text":"All three algorithms sample the same Boltzmann distribution. Overlaying them confirms that the choice of algorithm does not affect the physics, only the efficiency.\n\nplot_importance_sampling(\n    [res_meta, res_hb, res_gla],\n    [\"Metropolis\", \"HeatBath\", \"Glauber\"]\n)\n\nprintln(\"Average energy per spin:\")\nprintln(\"  Exact      : \", round(mean(get_centers(exact_logdos) .* P_exact); digits=3))\nprintln(\"  Metropolis : \", round(res_meta.avg_E; digits=3))\nprintln(\"  HeatBath   : \", round(res_hb.avg_E;   digits=3))\nprintln(\"  Glauber    : \", round(res_gla.avg_E;   digits=3))\n\n\n\nThis page was generated using Literate.jl.","title":"Comparison"},{"category":"section","location":"helper/#Helper-Utilities","page":"Helper","text":"This page groups lower-level tools used by algorithms and model packages.","title":"Helper Utilities"},{"category":"section","location":"helper/#Numeric-helpers","page":"Helper","text":"log_sum: numerically stable log-sum operations\nbinary_search: utility for sorted-domain lookups\nlogistic: logistic helper used in acceptance rules\nkldivergence: histogram/function divergence helper","title":"Numeric helpers"},{"category":"section","location":"helper/#RNG-helper","page":"Helper","text":"MutableRandomNumbers is a lightweight utility for deterministic random-number replay and control in workflows that need mutable RNG-like streams.","title":"RNG helper"},{"category":"section","location":"helper/#Event-handler-backends","page":"Helper","text":"These structures back event selection and queue-based scheduling in continuous-time samplers.","title":"Event-handler backends"},{"category":"function","location":"helper/#MonteCarloX.log_sum","page":"Helper","text":"log_sum(a::Real,b::Real)\n\nReturn result of logarithmic sum c = ln(A+B) = a + ln(1+e^b-a) where C = e^c = A+B = e^a + e^b.\n\nThis is useful for sums that involve elements that span multiple orders of magnitude, e.g., the partition sum that is required as normalization factor during reweighting.\n\nExamples\n\njulia> exp(MonteCarloX.log_sum(log(2.), log(3.)))\n5.000000000000001\n\n\n\n\n\n\nlog_sum(values::AbstractVector{<:Real})\n\nStable reduction of log-weights: log(sum(exp.(values))).\n\n\n\n\n\n","title":"MonteCarloX.log_sum"},{"category":"function","location":"helper/#MonteCarloX.binary_search","page":"Helper","text":"binary_search(sorted::AbstractVector{T}, value::T)::Int where {T<:Real}\n\nPerform a binary search to return the index i of an sorted array such that sorted[i-1] < value <= sorted[i]\n\nExamples\n\njulia> MonteCarloX.binary_search([1.,2.,3.,4.],2.5)\n3\n\njulia> MonteCarloX.binary_search([1,2,3,4],2)\n2\n\n\n\n\n\n","title":"MonteCarloX.binary_search"},{"category":"function","location":"helper/#MonteCarloX.logistic","page":"Helper","text":"logistic(x::Real)\n\nNumerically stable logistic sigmoid:\n\nσ(x) = 1 / (1 + exp(-x))\n\n\n\n\n\n","title":"MonteCarloX.logistic"},{"category":"function","location":"helper/#StatsBase.kldivergence","page":"Helper","text":"kldivergence(P::Histogram, Q::Function)\n\nKullback-Leibler divergence between an empirical distribution (measured) and a reference distribution (analytic)\n\nSo far this is defined only for 1-dimensional distributions of type StatsBase.Histogram\n\n\n\n\n\n","title":"StatsBase.kldivergence"},{"category":"type","location":"helper/#MonteCarloX.MutableRandomNumbers","page":"Helper","text":"MutableRandomNumbers([rng_base=GLOBAL_RNG], size, mode:=static)\n\nCreate a MutableRandomNumbers RNG object with a vector of size size containing floating-point randomnumbers initially generated with `rngbase`. Random numbers are then generated sequentially from this vector. The RNG object can be initialized in two modes:\n\n:static - then there is an exception thrown once all random numbers are used\n:dynamic - then there are new random numbers generated on the flow from the (copied) rng\n\nExamples\n\njulia> rng = MutableRandomNumbers(MersenneTwister(1234),100);\n\njulia> x1 = rand(rng, 2)\n2-element Array{Float64,1}:\n 0.5908446386657102\n 0.7667970365022592\n\njulia> rng = MersenneTwister(1234);\n\njulia> x2 = rand(rng, 2)\n2-element Array{Float64,1}:\n 0.5908446386657102\n 0.7667970365022592\n\njulia> x1 == x2\ntrue\n\nImportantly, the random numbers can be accessed and manipulated as in ordinary array objects.\n\njulia> rng[1]\n0.5908446386657102\njulia> rng[3] = 0.2\njulia> rand(rng)\n0.2\n\nUse reset! in order to rerun the (manipulated) random number sequence.\n\njulia> reset!(rng)\n\n\n\n\n\n\n","title":"MonteCarloX.MutableRandomNumbers"},{"category":"method","location":"helper/#MonteCarloX.reset!-Tuple{MutableRandomNumbers, Int64}","page":"Helper","text":"reset!(rng::MutableRandomNumbers, [index::Int=0])\n\nReset the state of a MutableRandomNumbers object rng to index. Default resets the RNG object to the pre-initial index (0)\n\n\n\n\n\n","title":"MonteCarloX.reset!"},{"category":"type","location":"helper/#MonteCarloX.ListEventRateSimple","page":"Helper","text":"ListEventRateSimple{T}\n\nSimplest event manager for a list of events of type T with a static list of rates.\n\nAPI implemented\n\nlength(event_handler)\ngetindex(event_handler, index)\nsetindex!(event_handler, value, index)\n\n\n\n\n\n","title":"MonteCarloX.ListEventRateSimple"},{"category":"type","location":"helper/#MonteCarloX.ListEventRateActiveMask","page":"Helper","text":"ListEventRateActiveMask{T}\n\nEvent manager with explicit active-mask tracking for sparse active rates.\n\n\n\n\n\n","title":"MonteCarloX.ListEventRateActiveMask"},{"category":"type","location":"helper/#MonteCarloX.EventQueue","page":"Helper","text":"EventQueue{T}([start_time::Float64])\n\nOrdered time-event queue storing (time, event) tuples.\n\nAPI implemented\n\nlength(event_handler)\ngetindex(event_handler, index)\npopfirst!(event_handler)\nadd!(event_handler, tuple_time_event)\nget_time(event_handler)\nset_time!(event_handler, time)\n\n\n\n\n\n","title":"MonteCarloX.EventQueue"},{"category":"section","location":"continuous_time_sampling_algorithms/#Continuous-Time-Sampling-Algorithms","page":"Continuous-Time Sampling","text":"Continuous-time Monte Carlo in MonteCarloX is event-driven. You sample when the next event happens and which event happens.","title":"Continuous-Time Sampling Algorithms"},{"category":"section","location":"continuous_time_sampling_algorithms/#Why-this-differs-from-Metropolis-style-sampling","page":"Continuous-Time Sampling","text":"Importance sampling focuses on stationary distributions.\nContinuous-time sampling focuses on trajectories in real/simulation time.\n\nConceptually, trajectories can be viewed as states in path space. The continuous-time interface is a computational specialization for explicit event-time dynamics.\n\nPath-space notation:\n\ntrajectory omega = (x_t)_t in 0T\ntarget path distribution pi(omega) = p(omega mid lambda)","title":"Why this differs from Metropolis-style sampling"},{"category":"section","location":"continuous_time_sampling_algorithms/#Gillespie-workflow","page":"Continuous-Time Sampling","text":"At each step:\n\ncompute total rate\nsample waiting time mathrmdt sim mathrmExp(lambda_mathrmtot)\nsample event index proportional to rates\nadvance time and apply event update\n\nGillespie stores steps and current time.","title":"Gillespie workflow"},{"category":"section","location":"continuous_time_sampling_algorithms/#Minimal-loop","page":"Continuous-Time Sampling","text":"using Random\nusing MonteCarloX\n\nalg = Gillespie(MersenneTwister(10))\nrates = [0.5, 1.0]  # e.g. birth, death\nfor _ in 1:10000\n    t, event = step!(alg, rates)\n    # apply event to your state\n    # update rates from new state\nend","title":"Minimal loop"},{"category":"section","location":"continuous_time_sampling_algorithms/#step!-vs-advance!","page":"Continuous-Time Sampling","text":"step!: one event at a time (full manual control)\nadvance!: run until total_time, with optional callbacks (measure!, update!)\n\nExample with explicit state + event source:\n\nusing Random\nusing MonteCarloX\n\nsys = Dict(:N => 30)\nevent_source(sys::Dict{Symbol,Int}) = [0.2 * sys[:N], 0.1 * sys[:N]]\nalg = Gillespie(MersenneTwister(11))\n\nmodify_cb = (state, event, t) -> begin\n    if event == 1\n        state[:N] += 1\n    elseif event == 2\n        state[:N] = max(0, state[:N] - 1)\n    end\nend\n\nadvance!(alg, sys, 20.0; modify!=modify_cb)","title":"step! vs advance!"},{"category":"section","location":"continuous_time_sampling_algorithms/#Event-sources-supported","page":"Continuous-Time Sampling","text":"raw vectors of rates\nStatsBase weights\nrate-based event handlers (AbstractEventHandlerRate)\ntime-ordered event queues (AbstractEventHandlerTime)\ncallback rates_at_time(t)","title":"Event sources supported"},{"category":"section","location":"continuous_time_sampling_algorithms/#Low-level-building-blocks","page":"Continuous-Time Sampling","text":"next_time: waiting-time sampling (homogeneous or thinning-based)\nnext_event: event-index sampling\nnext: one combined draw (mathrmdt textevent)","title":"Low-level building blocks"},{"category":"section","location":"continuous_time_sampling_algorithms/#Example-map-(algorithm-application)","page":"Continuous-Time Sampling","text":"Birth-death dynamics (Gillespie): examples/stochastic_processes/gillespie_birth_death.ipynb\nReaction-network dynamics (Gillespie): examples/stochastic_processes/gillespie_dimerization.ipynb\nPoisson primitives / low-level event draws: examples/stochastic_processes/kmc_poisson.ipynb","title":"Example map (algorithm ↔ application)"},{"category":"section","location":"continuous_time_sampling_algorithms/#API-reference","page":"Continuous-Time Sampling","text":"","title":"API reference"},{"category":"type","location":"continuous_time_sampling_algorithms/#MonteCarloX.AbstractKineticMonteCarlo","page":"Continuous-Time Sampling","text":"AbstractKineticMonteCarlo <: AbstractAlgorithm\n\nBase type for continuous-time kinetic Monte Carlo algorithms.\n\n\n\n\n\n","title":"MonteCarloX.AbstractKineticMonteCarlo"},{"category":"type","location":"continuous_time_sampling_algorithms/#MonteCarloX.Gillespie","page":"Continuous-Time Sampling","text":"Gillespie <: AbstractKineticMonteCarlo\n\nGillespie algorithm for continuous-time event-driven sampling.\n\nFields\n\nrng::AbstractRNG: Random number generator\nsteps::Int: Number of events sampled\ntime::Float64: Current simulation time\n\n\n\n\n\n","title":"MonteCarloX.Gillespie"},{"category":"function","location":"continuous_time_sampling_algorithms/#MonteCarloX.next","page":"Continuous-Time Sampling","text":"next(alg::AbstractKineticMonteCarlo, rates::AbstractVector)\n\nDraw next event waiting time and event id from raw rates.\n\nFor zero total rate, returns (Inf, 0).\n\n\n\n\n\nnext(alg::AbstractKineticMonteCarlo, rates::AbstractVector)\n\nDraw next event waiting time and event id from raw rates (StatsBase.AbstractWeights is also an AbstractVector).\n\nFor zero total rate, returns (Inf, 0).\n\n\n\n\n\nnext(alg::AbstractKineticMonteCarlo, event_handler::AbstractEventHandlerRate)\n\nDraw next event waiting time and event from an event handler.\n\n\n\n\n\nnext(alg::AbstractKineticMonteCarlo, event_handler::AbstractEventHandlerTime)\n\nDraw next event from a time-ordered event queue.\n\n\n\n\n\nnext(alg::AbstractKineticMonteCarlo, ratesattime::Function)\n\nDraw next event waiting time and event from a time-dependent rates function.\n\nrates_at_time is called as rates_at_time(alg.time) and should return either an AbstractVector, AbstractWeights, or AbstractEventHandlerRate.\n\n\n\n\n\n","title":"MonteCarloX.next"},{"category":"function","location":"continuous_time_sampling_algorithms/#MonteCarloX.step!","page":"Continuous-Time Sampling","text":"step!(alg::AbstractKineticMonteCarlo, event_source)\n\nPerform one kinetic Monte Carlo step from an event_source (rates or an event handler).\n\nUpdates alg.time and alg.steps internally and returns (t_new, event).\n\nIf dt=Inf then this is reflected in the algorithm.time and returned correspondingly If event is nothing, then this is returned as well.\n\n\n\n\n\n","title":"MonteCarloX.step!"},{"category":"function","location":"continuous_time_sampling_algorithms/#MonteCarloX.next_time","page":"Continuous-Time Sampling","text":"next_time(rng::AbstractRNG, rate_generation::Number)::Float64\n\nDraw next waiting time for a homogeneous Poisson event stream.\n\n\n\n\n\nnext_time(rng::AbstractRNG, rate::Function, rate_generation::Real)::Real\n\nDraw next waiting time for an inhomogeneous Poisson stream using thinning.\n\n\n\n\n\n","title":"MonteCarloX.next_time"},{"category":"function","location":"continuous_time_sampling_algorithms/#MonteCarloX.next_event","page":"Continuous-Time Sampling","text":"next_event(rng::AbstractRNG, rates::Union{AbstractWeights, AbstractVector})::Int\n\nDraw one event index proportional to rates.\n\n\n\n\n\n","title":"MonteCarloX.next_event"},{"category":"function","location":"continuous_time_sampling_algorithms/#MonteCarloX.advance!","page":"Continuous-Time Sampling","text":"advance!(alg::AbstractKineticMonteCarlo, sys, total_time; t0=0, measure!=measure!, modify!=modify!, ckpt=nothing, checkpoint_interval=nothing)\n\nAdvance system sys using alg until total_time.\n\nLoop order per step:\n\nstep!         — draw next event from event_source(sys)\nmeasure!      — observe before modification: measure!(sys, event, t)\nmodify!       — apply event to state:        modify!(sys, event, t)\ncheckpoint!   — optional: if ckpt::CheckpointSession and                   checkpoint_interval are provided, write a checkpoint                   every checkpoint_interval steps.\n\nStops early if the event source is exhausted or total time is reached.\n\nCheckpoint usage\n\nckpt = init_checkpoint(\"sim/ckpt.mcx\", (alg=alg, sys=sys); step=0)\nadvance!(alg, sys, 1e6; ckpt=ckpt, checkpoint_interval=1000)\n\n\n\n\n\n","title":"MonteCarloX.advance!"},{"category":"method","location":"continuous_time_sampling_algorithms/#MonteCarloX.reset!-Tuple{AbstractKineticMonteCarlo}","page":"Continuous-Time Sampling","text":"reset!(alg::AbstractKineticMonteCarlo)\n\nReset kinetic Monte Carlo statistics (steps, time) to zero.\n\n\n\n\n\n","title":"MonteCarloX.reset!"},{"category":"section","location":"generated/checkpointing/#Checkpointing","page":"Checkpointing","text":"Demonstrate checkpoint/restore for a single-chain Monte Carlo simulation. We verify that a run interrupted at a checkpoint and then continued produces identical results to an uninterrupted reference run.\n\nThis works because checkpointing serializes both the system state and the algorithm state (including the RNG), so the restored chain continues on the exact same trajectory.\n\nusing Random, Test\nusing MonteCarloX","title":"Checkpointing"},{"category":"section","location":"generated/checkpointing/#System-definition","page":"Checkpointing","text":"Same double-well potential as in the parallel-chains example.\n\nmutable struct System\n    x::Float64\nend\n\nE(sys::System) = 1/4*(sys.x^2 - 2)^2\n\nfunction update!(sys::System, alg::AbstractImportanceSampling; delta=0.1)\n    x_new = sys.x + delta * randn(alg.rng)\n    accept!(alg, E(System(x_new)), E(sys)) && (sys.x = x_new)\nend","title":"System definition"},{"category":"section","location":"generated/checkpointing/#Parameters","page":"Checkpointing","text":"const CI_MODE = get(ENV, \"MCX_SMOKE\", get(ENV, \"MCX_CI\", \"false\")) == \"true\"\n\nn_total  = CI_MODE ? 100 : 1000      # total number of samples\nn_sweep  = 10                         # sweeps between samples\nn_half   = n_total ÷ 2               # checkpoint after this many samples\n\nseed = 42\nβ    = 2.0","title":"Parameters"},{"category":"section","location":"generated/checkpointing/#Reference-run-(uninterrupted)","page":"Checkpointing","text":"Run the full simulation in one go and record the time series.\n\nref_sys = System(0.0)\nref_alg = Metropolis(Xoshiro(seed); β=β)\n\nref_xs = Vector{Float64}(undef, n_total)\nfor j in 1:n_total\n    for _ in 1:n_sweep; update!(ref_sys, ref_alg); end\n    ref_xs[j] = ref_sys.x\nend\nprintln(\"Reference run: $(n_total) samples, final x = $(round(ref_sys.x; digits=6))\")","title":"Reference run (uninterrupted)"},{"category":"section","location":"generated/checkpointing/#Checkpointed-run","page":"Checkpointing","text":"Run the first half, checkpoint, destroy objects, restore, continue.\n\nckpt_dir  = mktempdir()\nckpt_file = joinpath(ckpt_dir, \"ckpt.mcx\")","title":"Checkpointed run"},{"category":"section","location":"generated/checkpointing/#First-half","page":"Checkpointing","text":"sys = System(0.0)\nalg = Metropolis(Xoshiro(seed); β=β)\n\nckpt = init_checkpoint(ckpt_file, (sys=sys, alg=alg, sample=0))\n\nckpt_xs = Vector{Float64}(undef, n_total)\nfor j in 1:n_half\n    for _ in 1:n_sweep; update!(sys, alg); end\n    ckpt_xs[j] = sys.x\nend\n\ncheckpoint!(ckpt; sample=n_half)\nprintln(\"Checkpoint written at sample $(n_half), x = $(round(sys.x; digits=6))\")\n\nVerify first half already matches\n\n@assert ckpt_xs[1:n_half] == ref_xs[1:n_half] \"First half must match reference\"","title":"First half"},{"category":"section","location":"generated/checkpointing/#Destroy-and-restore","page":"Checkpointing","text":"Simulate a restart: forget sys and alg, then restore from file.\n\nckpt  = restore_checkpoint(ckpt_file)\nsys   = ckpt.sys\nalg   = ckpt.alg\nstart = ckpt.sample + 1\nprintln(\"Restored from checkpoint: sample=$(ckpt.sample), x = $(round(sys.x; digits=6))\")","title":"Destroy and restore"},{"category":"section","location":"generated/checkpointing/#Second-half","page":"Checkpointing","text":"for j in start:n_total\n    for _ in 1:n_sweep; update!(sys, alg); end\n    ckpt_xs[j] = sys.x\nend\n\nClean up checkpoint file after successful completion.\n\nfinalize!(ckpt)\nprintln(\"Resumed run complete: $(n_total) samples, final x = $(round(sys.x; digits=6))\")","title":"Second half"},{"category":"section","location":"generated/checkpointing/#Verify-identical-trajectories","page":"Checkpointing","text":"@assert ckpt_xs == ref_xs \"Checkpointed run must exactly match reference run\"\nprintln(\"✓ Checkpointed trajectory is identical to uninterrupted reference.\")","title":"Verify identical trajectories"},{"category":"section","location":"generated/checkpointing/#Summary","page":"Checkpointing","text":"The checkpointing API:\n\nckpt = init_checkpoint(file, (sys=sys, alg=alg, sweep=0))   # create session\ncheckpoint!(ckpt; sweep=n)                                    # save state\nckpt = restore_checkpoint(file)                               # restore session\nckpt.sys, ckpt.alg, ckpt.sweep                               # access fields\nfinalize!(ckpt)                                               # clean up\n\n\n\nThis page was generated using Literate.jl.","title":"Summary"},{"category":"section","location":"monte_carlo_fundamentals/#Monte-Carlo-Fundamentals","page":"Monte Carlo Fundamentals","text":"Monte Carlo methods estimate expectations by sampling. Let X be a random variable with target density or mass function pi(x), and let f be an observable. The central quantity is\n\nmathbbE_pif(X) = int f(x)pi(x)mathrmdx\n\nwith the integral understood as a sum in discrete spaces. Given samples x_1 dots x_n distributed according to pi, Monte Carlo uses\n\nmathbbE_pif(X) approx frac1nsum_i=1^n f(x_i)","title":"Monte Carlo Fundamentals"},{"category":"section","location":"monte_carlo_fundamentals/#1)-What-is-being-sampled?","page":"Monte Carlo Fundamentals","text":"Monte Carlo workflows differ mainly in the object whose distribution you sample.\n\nState sampling: distributions over states x\nTrajectory sampling: distributions over paths omega = (x_t)_t in 0T","title":"1) What is being sampled?"},{"category":"section","location":"monte_carlo_fundamentals/#2)-State-sampling:-equilibrium-ensembles","page":"Monte Carlo Fundamentals","text":"For equilibrium systems, the target distribution pi(x) arises from a Hamiltonian or energy functional.","title":"2) State sampling: equilibrium ensembles"},{"category":"section","location":"monte_carlo_fundamentals/#Canonical-ensemble","page":"Monte Carlo Fundamentals","text":"pi(x) = frac1Z(beta) e^-beta E(x)\n\nwhere beta = 1(k_B T) is the inverse temperature and Z(beta) = sum_x e^-beta E(x) is the partition function. Monte Carlo sampling produces configurations x distributed according to this Boltzmann weight.","title":"Canonical ensemble"},{"category":"section","location":"monte_carlo_fundamentals/#Generalized-ensembles","page":"Monte Carlo Fundamentals","text":"For rugged energy landscapes or to access rare events, generalized ensembles modify the sampling measure.\n\nMulticanonical: pi_textmuca(x) propto e^-beta_textref E(x)  w(E(x)), where w(E) is a tuned weight to flatten the energy histogram.\n\nWang-Landau: iteratively updates w(E) to achieve flat histogram sampling, estimating the density of states Omega(E).","title":"Generalized ensembles"},{"category":"section","location":"monte_carlo_fundamentals/#Extended-ensembles","page":"Monte Carlo Fundamentals","text":"Parallel tempering (replica exchange) introduces multiple replicas at different temperatures beta_i and allows exchanges between them. The extended state is (beta_i x_i), and the target distribution factorizes as\n\nPi((beta_i x_i)) = prod_i frac1Z(beta_i) e^-beta_i E(x_i)\n\nExchange moves (beta_i x_i) leftrightarrow (beta_j x_j) enable sampling of low-temperature states via high-temperature replicas.","title":"Extended ensembles"},{"category":"section","location":"monte_carlo_fundamentals/#3)-Trajectory-sampling:-kinetic-processes","page":"Monte Carlo Fundamentals","text":"For non-equilibrium or time-dependent processes, the target is a distribution over entire trajectories omega = (x_t)_tin0T.","title":"3) Trajectory sampling: kinetic processes"},{"category":"section","location":"monte_carlo_fundamentals/#Event-driven-sampling","page":"Monte Carlo Fundamentals","text":"Given state-dependent event rates r_k(x), the total rate is r_texttot = sum_k r_k(x). The waiting time tau to the next event is exponentially distributed:\n\np(tau) = r_texttot(x) e^-r_texttot(x) tau\n\nAfter drawing tau, an event k is selected with probability r_k(x)r_texttot(x). The process then advances: t to t + tau and x to x (modified according to event k).\n\nThis defines a path-space distribution where each trajectory omega has probability weight proportional to the product of exponential waiting times and conditional event probabilities.","title":"Event-driven sampling"},{"category":"section","location":"monte_carlo_fundamentals/#4)-Markov-chain-convergence","page":"Monte Carlo Fundamentals","text":"For ergodic Markov chains:\n\nDetailed balance: pi(x) T(x leftarrow x) = pi(x) T(x leftarrow x) ensures pi is stationary.\nErgodiciy: every state can be reached from every other state (eventually).\n\nUnder these conditions, the chain converges to pi regardless of the initial state. The rate of convergence depends on the algorithm and the target distribution's geometry (e.g., barrier heights, correlations).","title":"4) Markov chain convergence"},{"category":"section","location":"monte_carlo_fundamentals/#5)-Sampling-vs.-integration","page":"Monte Carlo Fundamentals","text":"Monte Carlo gives stochastic estimates of expectations:\n\nhatf = frac1nsum_i=1^n f(x_i) quad x_i sim pi\n\nThe statistical error scales as 1sqrtn, independent of dimensionality — this is the key advantage over deterministic quadrature. However, correlated samples from a Markov chain increase the asymptotic variance:\n\nsigma^2_textasymp = sigma^2 left(1 + 2sum_k=1^infty rho_kright)\n\nwhere rho_k is the autocorrelation at lag k. This is quantified by the autocorrelation time tau_textint, so the effective sample size is n  tau_textint.","title":"5) Sampling vs. integration"},{"category":"section","location":"generated/contact_process/#Contact-Process-on-a-Network","page":"Contact Process on a Network","text":"The contact process is a continuous-time Markov process modeling infection spread on a network. Each node is either inactive (healthy) or active (infected). Active nodes recover at rate mu, while inactive nodes get infected by active neighbors at rate lambda * (active_neighbors / degree). Additionally, spontaneous infection occurs at rate h.\n\nThis example demonstrates using MonteCarloX's Gillespie algorithm with event-driven simulation on a graph structure.\n\nusing Random, Plots, Statistics\nusing Graphs\nusing MonteCarloX","title":"Contact Process on a Network"},{"category":"section","location":"generated/contact_process/#System-definition","page":"Contact Process on a Network","text":"A simplified ContactProcess structure with direct rate updates.\n\nmutable struct ContactProcess\n    network::SimpleDiGraph{Int}\n    neurons::Vector{Int8}\n    active_incoming_neighbors::Vector{Int}\n    rates::Vector{Float64}\n    mu::Float64\n    lambda::Float64\n    h::Float64\nend\n\nfunction ContactProcess(N, p, mu, lambda, h; initial=\"empty\", seed=42)\n    network = erdos_renyi(N, p; is_directed=true, seed=seed)\n    neurons = initial == \"full\" ? ones(Int8, N) : zeros(Int8, N)\n    active_incoming_neighbors = initial == \"full\" ? ones(Int, N) : zeros(Int, N)\n    rates = initial == \"full\" ? fill(mu, N) : fill(h, N)\n    return ContactProcess(network, neurons, active_incoming_neighbors, rates, mu, lambda, h)\nend\n\nfunction MonteCarloX.modify!(sys::ContactProcess, event::Int, t)\n    dstate = sys.neurons[event] == 0 ? 1 : -1\n    sys.neurons[event] = 1 - sys.neurons[event]\n    sys.rates[event]   = dstate == 1 ? sys.mu : sys.h + sys.lambda * sys.active_incoming_neighbors[event] / length(inneighbors(sys.network, event))\n\n    for nn in outneighbors(sys.network, event)\n        sys.active_incoming_neighbors[nn] += dstate\n        if sys.neurons[nn] == 0\n            sys.rates[nn] = sys.h + sys.lambda * sys.active_incoming_neighbors[nn] / length(inneighbors(sys.network, nn))\n        end\n    end\n    return nothing\nend","title":"System definition"},{"category":"section","location":"generated/contact_process/#Parameters","page":"Contact Process on a Network","text":"We use a dense ER graph (p=0.5) to approximate mean-field conditions where the analytical prediction ρ = h / (mu - lambda) holds for the sub-critical regime (lambda < mu). Note that the contact process reaches steady state only after a long time; for the SMOKE tests we use shorter T but the full run should show the activity approaching the analytical prediction.\n\nconst CI_MODE = get(ENV, \"MCX_SMOKE\", get(ENV, \"MCX_CI\", \"false\")) == \"true\"\n\nN     = CI_MODE ? 100 : 1_000\np     = 0.2\nmu    = 1.0\nlambda = mu * 0.9  # sub-critical: lambda < mu\nh     = 1e-1\nT     = CI_MODE ? 100.0 : 1_000.0\ndt_step = 10.0\nmeasure_times = collect(0.0:dt_step:T);\nnothing #hide","title":"Parameters"},{"category":"section","location":"generated/contact_process/#Run-simulation","page":"Contact Process on a Network","text":"sys = ContactProcess(N, p, mu, lambda, h; initial=\"empty\", seed=42)\nalg = Gillespie(MersenneTwister(42))\n\nmeasurements = Measurements(\n    [:activity => (s -> sum(s.neurons)) => Float64[]],\n    measure_times,\n)\nmeasure!(measurements, sys, alg.time)\n\nSimulate and measure at discrete time points\n\nelapsed_time = @elapsed begin\n    while alg.time <= T\n        t_new, event = step!(alg, sys.rates)\n        measure!(measurements, sys, t_new)\n        modify!(sys, event, t_new)\n    end\nend\n\nExtract results\n\ntimes = MonteCarloX.times(measurements)\nactivity = MonteCarloX.data(measurements, :activity)\n\nPrint statistics\n\nprintln(\"Contact process simulation complete (time: $(round(elapsed_time; digits=3))s)\")","title":"Run simulation"},{"category":"section","location":"generated/contact_process/#Plot:-activity-time-series","page":"Contact Process on a Network","text":"p = plot(times, activity/N; lw=2, label=\"Activity\",\n         xlabel=\"Time\", ylabel=\"Active nodes (normalized)\",\n         title=\"Contact process (sub-critical: λ/μ = $(lambda/mu))\",\n         size=(700, 280), margin=5Plots.mm)\n\ncf. Martinello et al. PRX (2017)\n\nrho_mf = (lambda-mu-h + sqrt(4*h*lambda + (lambda-mu-h)^2)) / (2*lambda)\nhline!(p, [rho_mf]; color=:red, linestyle=:dash, label=\"MF prediction\")\np\n\n\n\nThis page was generated using Literate.jl.","title":"Plot: activity time series"},{"category":"section","location":"generated/coin_flip/#Bayesian-Inference:-Coin-Flip-with-Importance-Sampling","page":"Coin Flip (Bayesian inference)","text":"We demonstrate importance sampling via Metropolis: proposals from a random walk, acceptance based on the posterior ratio (prior × likelihood). This pattern is general and directly compatible with advanced algorithms in MonteCarloX.jl such as multicanonical and Wang-Landau sampling.\n\nusing Random, Statistics, Distributions, Plots\nusing MonteCarloX","title":"Bayesian Inference: Coin Flip with Importance Sampling"},{"category":"section","location":"generated/coin_flip/#CI-parameters","page":"Coin Flip (Bayesian inference)","text":"const CI_MODE = get(ENV, \"MCX_SMOKE\", get(ENV, \"MCX_CI\", \"false\")) == \"true\"\n\nn_steps  = CI_MODE ? 1_000  : 100_000\nburn_in  = CI_MODE ? 200    : 10_000","title":"CI parameters"},{"category":"section","location":"generated/coin_flip/#Data-and-model","page":"Coin Flip (Bayesian inference)","text":"We observe 100 coin flips with 61 heads and 39 tails. The conjugate prior is textBeta(22), giving an exact posterior textBeta(alpha + textheads beta + texttails) against which we validate the MCMC result.\n\nA key advantage of MCMC is that accept! only needs the unnormalized log-posterior — prior plus likelihood — without computing the evidence.\n\nn_heads, n_tails = 61, 39\nα_prior, β_prior = 2.0, 2.0\nprior            = Beta(α_prior, β_prior)\nposterior_exact  = Beta(α_prior + n_heads, β_prior + n_tails)\n\nlogprior(θ)      = logpdf(prior, θ)\nloglikelihood(θ) = n_heads * log(θ) + n_tails * log1p(-θ)\nlogposterior(θ)  = logprior(θ) + loglikelihood(θ)\n\nprintln(\"Data            : $(n_heads) heads, $(n_tails) tails out of $(n_heads+n_tails)\")\nprintln(\"Exact posterior : Beta($(α_prior + n_heads), $(β_prior + n_tails))\")","title":"Data and model"},{"category":"section","location":"generated/coin_flip/#Metropolis-sampling","page":"Coin Flip (Bayesian inference)","text":"A Gaussian random walk proposes new values of theta in (01). The accept! interface of MonteCarloX.jl evaluates the log-posterior ratio and handles the acceptance decision, tracking statistics automatically.\n\nfunction update!(alg::Metropolis, θ, Δ)\n    θ_new = θ + Δ * randn(alg.rng)\n    if 0.0 < θ_new < 1.0\n        accept!(alg, θ_new, θ) && (θ = θ_new)\n    end\n    return θ\nend\n\nfunction run_metropolis(logposterior, prior; seed=2026, Δ=0.03)\n    rng     = MersenneTwister(seed)\n    alg     = Metropolis(rng, logposterior)\n    θ       = rand(rng, prior)\n    samples = Float64[]\n    for _ in 1:burn_in\n        θ = update!(alg, θ, Δ)\n    end\n    reset!(alg)\n    for _ in 1:n_steps\n        θ = update!(alg, θ, Δ)\n        push!(samples, θ)\n    end\n    return samples, alg\nend\n\nsamples, alg = run_metropolis(logposterior, prior)\n\nprintln(\"Step size Δ       : 0.03\")\nprintln(\"Acceptance rate   : \", round(acceptance_rate(alg); digits=3))\nprintln(\"Samples collected : \", length(samples))","title":"Metropolis sampling"},{"category":"section","location":"generated/coin_flip/#Results","page":"Coin Flip (Bayesian inference)","text":"The MCMC posterior mean and 95% credible interval match the exact Beta posterior closely, confirming correct implementation. The plot shows the Bayesian update from prior to posterior, with the MCMC histogram overlaid.\n\nprintln(\"Posterior mean:  MCMC = \", round(mean(samples);          digits=4),\n                       \"  exact = \", round(mean(posterior_exact); digits=4))\nprintln(\"95% CI:  MCMC  = [\", round(quantile(samples,         0.025); digits=4),\n                    \", \",      round(quantile(samples,         0.975); digits=4), \"]\")\nprintln(\"         exact = [\", round(quantile(posterior_exact, 0.025); digits=4),\n                    \", \",      round(quantile(posterior_exact, 0.975); digits=4), \"]\")\n\nxgrid = range(0.3, 0.85; length=300)\nhistogram(samples; bins=50, normalize=:pdf, alpha=0.5,\n          label=\"MCMC samples\", xlabel=\"θ\", ylabel=\"Density\",\n          title=\"Coin-flip: prior → posterior\")\nplot!(xgrid, pdf.(prior, xgrid);\n      lw=2, color=:gray, ls=:dash, label=\"Prior Beta($(α_prior),$(β_prior))\")\nplot!(xgrid, pdf.(posterior_exact, xgrid);\n      lw=2, color=:black, label=\"Exact posterior\")\n\n\n\nThis page was generated using Literate.jl.","title":"Results"},{"category":"section","location":"generated/house_price_prediction/#Bayesian-Linear-Regression:-House-Price-Prediction","page":"Importance sampling: House Price Prediction","text":"We extend the coin-flip pattern to a multivariate problem: inferring the parameters of a linear price model from noisy observations. The same MonteCarloX.jl accept! interface handles the posterior ratio — prior plus likelihood — without any normalizing constant.\n\ny = beta_0 + beta_1 x + varepsilon qquad varepsilon sim mathcalN(0sigma^2)\n\nusing Random, Statistics, Distributions, Plots\nusing MonteCarloX","title":"Bayesian Linear Regression: House Price Prediction"},{"category":"section","location":"generated/house_price_prediction/#CI-parameters","page":"Importance sampling: House Price Prediction","text":"const CI_MODE = get(ENV, \"MCX_SMOKE\", get(ENV, \"MCX_CI\", \"false\")) == \"true\"\n\nn_steps  = CI_MODE ? 1_000  : 100_000\nburn_in  = CI_MODE ? 200    : 10_000","title":"CI parameters"},{"category":"section","location":"generated/house_price_prediction/#Synthetic-data","page":"Importance sampling: House Price Prediction","text":"We generate 50 house prices from a known ground-truth model. Working on a normalized scale improves numerical stability and keeps the prior specification simple and scale-free.\n\nβ0_true, β1_true, σ_true = 50_000.0, 1_500.0, 15_000.0   ## USD, USD/m², USD\n\nrng = MersenneTwister(42)\nn   = 50\nx   = Float64.(rand(rng, 90:460, n))\ny   = β0_true .+ β1_true .* x .+ σ_true .* randn(rng, n)\n\nx_mean, x_std = mean(x), std(x)\ny_mean, y_std = mean(y), std(y)\nx_norm = (x .- x_mean) ./ x_std\ny_norm = (y .- y_mean) ./ y_std\n\nprintln(\"Houses: $(n),  price range: \\$$(round(Int, minimum(y))) – \\$$(round(Int, maximum(y)))\")\nprintln(\"Ground truth: β₀ = $(β0_true),  β₁ = $(β1_true) USD/m²,  σ = $(σ_true) USD\")","title":"Synthetic data"},{"category":"section","location":"generated/house_price_prediction/#Model-and-priors","page":"Importance sampling: House Price Prediction","text":"Parameters are estimated on the normalized scale. We use weakly informative Normal priors and sample logsigma to enforce positivity.\n\nprior_β0   = Normal(0, 1)\nprior_β1   = Normal(0, 1)\nprior_logσ = Normal(log(0.5), 1)\n\nfunction loglikelihood(θ)\n    β0, β1, logσ = θ\n    σ = exp(logσ)\n    return -0.5 * sum((y_norm .- (β0 .+ β1 .* x_norm)).^2) / σ^2 - n * logσ\nend\n\nlogprior(θ)     = logpdf(prior_β0, θ[1]) + logpdf(prior_β1, θ[2]) + logpdf(prior_logσ, θ[3])\nlogposterior(θ) = logprior(θ) + loglikelihood(θ)","title":"Model and priors"},{"category":"section","location":"generated/house_price_prediction/#Metropolis-sampling","page":"Importance sampling: House Price Prediction","text":"A coordinate-wise Gaussian random walk proposes new parameter vectors. The three-parameter posterior is explored jointly; accept! evaluates the log-posterior ratio and updates the acceptance counter automatically.\n\nfunction run_metropolis(logposterior; seed=2026, Δ=0.05)\n    rng     = MersenneTwister(seed)\n    alg     = Metropolis(rng, logposterior)\n    θ       = [rand(rng, prior_β0), rand(rng, prior_β1), rand(rng, prior_logσ)]\n    samples = [Float64[] for _ in 1:3]\n    for _ in 1:burn_in\n        θ_new = θ .+ Δ .* randn(rng, 3)\n        accept!(alg, θ_new, θ) && (θ = θ_new)\n    end\n    reset!(alg)\n    for _ in 1:n_steps\n        θ_new = θ .+ Δ .* randn(rng, 3)\n        accept!(alg, θ_new, θ) && (θ = θ_new)\n        push!.(samples, θ)\n    end\n    return samples, alg\nend\n\nsamples, alg = run_metropolis(logposterior)\n\nprintln(\"Step size Δ       : 0.05 (all parameters)\")\nprintln(\"Acceptance rate   : \", round(acceptance_rate(alg); digits=3))\nprintln(\"Samples collected : \", length(samples[1]))","title":"Metropolis sampling"},{"category":"section","location":"generated/house_price_prediction/#Back-transform-to-SI-units","page":"Importance sampling: House Price Prediction","text":"Posterior samples on the normalized scale are analytically mapped back to the original units, preserving the full posterior uncertainty.\n\nβ1_si = (y_std / x_std) .* samples[2]\nβ0_si = y_mean .+ y_std .* samples[1] .- β1_si .* x_mean\nσ_si  = y_std .* exp.(samples[3])\n\nfor (name, s, truth, unit) in [\n        (\"β₀\", β0_si, β0_true, \"USD\"),\n        (\"β₁\", β1_si, β1_true, \"USD/m²\"),\n        (\"σ\",  σ_si,  σ_true,  \"USD\")]\n    lo, hi = round.(quantile(s, [0.025, 0.975]); digits=0)\n    println(\"$(name) = $(round(mean(s); digits=1))  [$(lo), $(hi)] $(unit)  (truth: $(truth))\")\nend","title":"Back-transform to SI units"},{"category":"section","location":"generated/house_price_prediction/#Posterior-predictive","page":"Importance sampling: House Price Prediction","text":"Overlaying 80 randomly drawn regression lines against the data visualises posterior uncertainty. The posterior mean line recovers the ground truth well.\n\nxline   = range(minimum(x), maximum(x); length=200)\nn_lines = min(80, length(β0_si))\nidx     = rand(1:length(β0_si), n_lines)\n\nplt_pred = scatter(x, y; alpha=0.7, ms=4, label=\"data\",\n                   xlabel=\"Area (m²)\", ylabel=\"Price (USD)\",\n                   title=\"Posterior predictive\", size=(700, 320),\n                   margin=5Plots.mm)\nfor i in idx\n    plot!(plt_pred, xline, β0_si[i] .+ β1_si[i] .* xline;\n          lw=1, alpha=0.08, color=:steelblue, label=\"\")\nend\nplot!(plt_pred, xline, mean(β0_si) .+ mean(β1_si) .* xline;\n      lw=2.5, color=:red, label=\"posterior mean\")\nplot!(plt_pred, xline, β0_true .+ β1_true .* xline;\n      lw=2, color=:black, ls=:dash, label=\"ground truth\")","title":"Posterior predictive"},{"category":"section","location":"generated/house_price_prediction/#Posterior-marginals","page":"Importance sampling: House Price Prediction","text":"Diagonal panels show the marginal posterior for each parameter; dashed lines mark the ground truth. All three parameters are well recovered.\n\nfunction marginal_panel(s, truth, xlabel, title; ticks=nothing)\n    p = histogram(s; bins=50, normalize=:pdf, alpha=0.6, label=\"\",\n                  xlabel=xlabel, ylabel=\"\", title=title,\n                  size=(300, 220))\n    ticks !== nothing && plot!(p; xticks=ticks)\n    vline!(p, [truth]; lw=2, ls=:dash, color=:black, label=\"truth\")\n    return p\nend\n\nt3(s) = round.(range(quantile(s, 0.01), quantile(s, 0.99); length=3); digits=0)\n\np_β0 = marginal_panel(β0_si, β0_true, \"β₀ (USD)\",    \"Intercept\"; ticks=t3(β0_si))\np_β1 = marginal_panel(β1_si, β1_true, \"β₁ (USD/m²)\", \"Slope\")\np_σ  = marginal_panel(σ_si,  σ_true,  \"σ (USD)\",     \"Noise\";     ticks=t3(σ_si))\n\nplot(p_β0, p_β1, p_σ; layout=(1,3), size=(900, 260), margin=5Plots.mm)\n\n\n\nThis page was generated using Literate.jl.","title":"Posterior marginals"},{"category":"section","location":"generated/pt_Ising2D/","page":"Parallel tempering: Ising 2D","text":"using Random, Statistics, StatsBase, Plots\nusing MonteCarloX, SpinSystems\n\n%%","title":"Parallel tempering: Ising 2D"},{"category":"section","location":"generated/pt_Ising2D/#Background","page":"Parallel tempering: Ising 2D","text":"Parallel tempering (replica exchange) runs multiple replicas at different inverse temperatures beta. Each replica performs local Metropolis sweeps, then neighboring replicas attempt an exchange.\n\nThe main practical benefit is robust sampling across continuous phase transitions and better exploration of rugged energy landscapes via repeated annealing across the temperature ladder.\n\nIn this example we keep the loop structure intentionally simple:\n\nthermalize,\nrun measurement sweeps,\nattempt exchanges,\ncompare sampled energy distributions to exact references.\n\n%%","title":"Background"},{"category":"section","location":"generated/pt_Ising2D/#Constants","page":"Parallel tempering: Ising 2D","text":"const CI_MODE = get(ENV, \"MCX_SMOKE\", get(ENV, \"MCX_CI\", \"false\")) == \"true\"\n\nL = 8\nnreplicas = CI_MODE ? 2 : 4\nnmeasurements = CI_MODE ? 200 : 20_000\nntherm_init = CI_MODE ? 20 : 2_000\nntherm_after_exchange = CI_MODE ? 1 : 20\nsweeps_between_exchange = CI_MODE ? 4 : 200\nmeasurement_interval = 1\n\nTmin = 1.5\nTmax = 3.0\nseed = 42\n\nnreplicas >= 2 || throw(ArgumentError(\"nreplicas must be >= 2\"))\nnmeasurements >= 1 || throw(ArgumentError(\"nmeasurements must be >= 1\"))\nsweeps_between_exchange >= 1 || throw(ArgumentError(\"sweeps_between_exchange must be >= 1\"))\nmeasurement_interval >= 1 || throw(ArgumentError(\"measurement_interval must be >= 1\"))\n\n%%","title":"Constants"},{"category":"section","location":"generated/pt_Ising2D/#Sweep-helper","page":"Parallel tempering: Ising 2D","text":"function sweep_replica!(sys, alg, L)\n    for _ in 1:(L * L)\n        spin_flip!(sys, alg)\n    end\n    return nothing\nend\n\n%%","title":"Sweep helper"},{"category":"section","location":"generated/pt_Ising2D/#Serial-PT-run","page":"Parallel tempering: Ising 2D","text":"betas = set_betas(nreplicas, inv(Tmax), inv(Tmin), :uniform)\n\nsystems = [Ising([L, L]) for _ in 1:nreplicas]\npt = ParallelTempering(betas; seed=seed, rng=MersenneTwister)\n\nfor r in 1:nreplicas\n    init!(systems[r], :random; rng=algorithm(pt, r).rng)\n    for _ in 1:ntherm_init\n        sweep_replica!(systems[r], algorithm(pt, r), L)\n    end\nend\n\nenergies = zeros(Float64, nreplicas)\nmags = zeros(Float64, nreplicas)\nmeas = Measurements([\n    :energies => (_ -> copy(energies)) => Vector{Vector{Float64}}(),\n    :mags => (_ -> copy(mags)) => Vector{Vector{Float64}}(),\n], interval=measurement_interval)\nindex_trace = Vector{Vector{Int}}()\n\nn_exchanges = nmeasurements ÷ sweeps_between_exchange\nlet sample_counter = 0\n    for exch in 1:n_exchanges\n        # re-thermalize after exchange\n        for r in 1:nreplicas\n            for _ in 1:ntherm_after_exchange\n                sweep_replica!(systems[r], algorithm(pt, r), L)\n            end\n        end\n\n        # measure\n        for _ in 1:sweeps_between_exchange\n            for r in 1:nreplicas\n                sweep_replica!(systems[r], algorithm(pt, r), L)\n                energies[r] = energy(systems[r])\n                mags[r] = magnetization(systems[r])\n            end\n            sample_counter += 1\n            n_before = length(data(meas, :energies))\n            measure!(meas, nothing, sample_counter)\n            if length(data(meas, :energies)) > n_before\n                push!(index_trace, copy(index(pt)))\n            end\n        end\n        # replica exchange\n        MonteCarloX.update!(pt, energies)\n    end\nend\n\nenergy_samples = [Float64[] for _ in 1:nreplicas]\nmag_samples = [Float64[] for _ in 1:nreplicas]\nenergy_trace = data(meas, :energies)\nmag_trace = data(meas, :mags)\n\n@inbounds for k in eachindex(energy_trace)\n    idxs = index_trace[k]\n    es = energy_trace[k]\n    ms = mag_trace[k]\n    for r in eachindex(idxs)\n        push!(energy_samples[idxs[r]], es[r])\n        push!(mag_samples[idxs[r]], ms[r])\n    end\nend\n\nrates = acceptance_rates(pt)\n\nprintln(\"PT Ising2D serial finished\")\nprintln(\"L = $(L), replicas = $(nreplicas)\")\nprintln(\"mean exchange acceptance = $(round(mean(rates), digits=4))\")\n\n%%","title":"Serial PT run"},{"category":"section","location":"generated/pt_Ising2D/#Plot-vs-exact","page":"Parallel tempering: Ising 2D","text":"for (i, β) in enumerate(betas)\n    println(\"beta[$i] = $(round(β, digits=4)), samples = $(length(energy_samples[i]))\")\nend\n\nexact_logdos = logdos_exact_ising2D(L)\nedges = get_edges(exact_logdos.bins[1])\nplots = Any[]\n\nfor (i, β) in enumerate(betas)\n    p_i = plot(xlabel=\"Energy\", ylabel=\"Probability\",\n               title=\"beta=$(round(β, digits=3))\", legend=:topright)\n\n    samples_i = energy_samples[i]\n    if !isempty(samples_i)\n        hist_i = fit(Histogram, samples_i, edges, closed=:left)\n        dist_i = StatsBase.normalize(hist_i; mode=:probability)\n        plot!(p_i, dist_i; label=\"PT serial\", lw=2, color=:steelblue)\n    end\n\n    dist_exact = distribution_exact_ising2D(L, β)\n    plot!(p_i, get_centers(dist_exact), dist_exact.values; label=\"Exact\", lw=2, color=:black, ls=:dash)\n    push!(plots, p_i)\nend\n\nncols = 2\nnrows = 2\nplot(plots...;\n    layout=(nrows, ncols),\n    size=(950, 720),\n    margin=3Plots.mm,\n    background_color=:white,\n    background_color_outside=:white)\n\n\n\nThis page was generated using Literate.jl.","title":"Plot vs exact"},{"category":"section","location":"build_your_own_system/#Build-Your-Own-System","page":"Build Your Own System","text":"MonteCarloX provides algorithms, not complete simulations. Your job is to define the system state and local update rules. The framework handles acceptance, event scheduling, and sampling infrastructure.","title":"Build Your Own System"},{"category":"section","location":"build_your_own_system/#Minimal-requirements","page":"Build Your Own System","text":"To use MonteCarloX algorithms, you need:\n\nSystem state type — your model's configuration\nLocal update function — proposes changes and uses accept! or step!\nQuantities needed by the algorithm — energy difference, event rates, etc.\n\nYou do not need to implement the full framework. Start simple and add advanced features incrementally.\n\n","title":"Minimal requirements"},{"category":"section","location":"build_your_own_system/#Discrete-state-sampling-(Metropolis,-Glauber,-HeatBath)","page":"Build Your Own System","text":"","title":"Discrete-state sampling (Metropolis, Glauber, HeatBath)"},{"category":"section","location":"build_your_own_system/#Core-pattern","page":"Build Your Own System","text":"using MonteCarloX\n\n# 1. Define system state\nmutable struct MySystem\n    # state variables\nend\n\n# 2. Compute energy (or log-weight)\nenergy(sys::MySystem, i) = # ... compute (local) total energy\n\n# 3. Local update proposes change and uses accept!\nfunction update!(sys::MySystem, alg::Metropolis; delta=0.1)\n    i = rand(alg.rng, 1:length(sys))\n    # backup old state\n    tmp = sys[i]\n    energy_old = energy(sys, i)\n    # local change\n    sys[i] += delta * (2 * rand(alg.rng) - 1)\n    energy_new = energy(sys, i)\n    if !accept!(alg, energy_new, energy_old)\n        sys[i] = tmp\n    end\nend\n\n# 4. Run the simulation\nalg = Metropolis(Xoshiro(42); β=1.0)\nsys = MySystem(...)\nfor step in 1:10_000\n    update!(sys, alg)\nend","title":"Core pattern"},{"category":"section","location":"build_your_own_system/#Checklist","page":"Build Your Own System","text":"Define your system state type.\nDefine the total energy (or log-weight) function.\nIn your update function: propose → compute energies → accept!(alg, E_new, E_old) → apply if accepted / revert if rejected.\nPass the RNG from alg.rng to random operations.\n\n","title":"Checklist"},{"category":"section","location":"build_your_own_system/#Continuous-time-sampling-(Gillespie)","page":"Build Your Own System","text":"","title":"Continuous-time sampling (Gillespie)"},{"category":"section","location":"build_your_own_system/#Core-pattern-2","page":"Build Your Own System","text":"using MonteCarloX\n\nmutable struct MyProcess <: AbstractSystem\n    # state variables\nend\n\n# 1. Provide event rates (must return a vector)\nfunction MonteCarloX.event_source(sys::MyProcess, t)\n    # compute rates for each possible event\n    return [rate1, rate2, ...]\nend\n\n# 2. Apply event (modify state in-place)\nfunction MonteCarloX.modify!(sys::MyProcess, event::Int, t)\n    # modify state based on event index\n    if event == 1\n        # birth event\n    elseif event == 2\n        # death event\n    end\n    return nothing\nend\n\n# 3. Run with step! or advance!\nalg = Gillespie(Xoshiro(42))\nsys = MyProcess(...)\nT = 100.0\n\n# Manual loop\nfor _ in 1:10_000\n    t, event = step!(alg, event_source(sys, alg.time))\n    event === nothing && break\n    modify!(sys, event, t)\nend\n\n# Or use advance! with callbacks\nadvance!(alg, sys, T;\n    rates=(state, t) -> event_source(state, t),\n    update!=(state, event, t) -> modify!(state, event, t),\n)","title":"Core pattern"},{"category":"section","location":"build_your_own_system/#Checklist-2","page":"Build Your Own System","text":"Define state type (subtype AbstractSystem).\nImplement event_source(state, t) returning event rate vector.\nImplement modify!(state, event, t) to apply state changes.\nUse step! for manual control or advance! for callback-based integration.\n\n","title":"Checklist"},{"category":"section","location":"build_your_own_system/#Measuring-observables","page":"Build Your Own System","text":"Measurements is an optional helper for scheduling observations:\n\nusing MonteCarloX\n\n# Define what to measure and when\n# The second argument is either:\n#   - An interval (e.g., 1:10 means measure every 10 steps)\n#   - A vector of specific times/steps (e.g., collect(0:10:100) for steps 0,10,20,...)\nmeasurements = Measurements([\n    :energy => (sys -> energy(sys)) => Float64[],\n    :magnetization => (sys -> magnetization(sys)) => Float64[],\n], interval=10)\n\n# At each measurement opportunity:\nmeasure!(measurements, sys, step_index)\n\n# Access results:\nenergy_data = measurements[:energy].data\n\nYou can measure manually with vectors if you prefer — Measurements just adds convenience.\n\n","title":"Measuring observables"},{"category":"section","location":"build_your_own_system/#Key-points","page":"Build Your Own System","text":"Algorithms are model-agnostic: the same Metropolis works for spin systems, Bayesian posteriors, or custom models.\nState management is yours: MonteCarloX never modifies your system directly; updates happen in your code or mediated by other packages (cf. SpinSystems).\nRNG is passed from algorithm: always use alg.rng for randomness.\nCheckpointing: serialize (e.g. sys and alg) for restart capability.\nParallel extensions build on the same interface: ParallelTempering, ParallelMulticanonical, etc.\n\nSee the SpinSystems package as example for system implementations.","title":"Key points"},{"category":"section","location":"importance_sampling_algorithms/#Importance-Sampling-Algorithms","page":"Importance Sampling","text":"Importance sampling in MonteCarloX is built around (local) proposals + acceptance rules. The defining feature is a discrete-step update loop (proposal → decision → update).\n\nWhile this is most commonly used for equilibrium sampling, the same machinery can be used in non-equilibrium protocols by changing parameters or target weights over steps.","title":"Importance Sampling Algorithms"},{"category":"section","location":"importance_sampling_algorithms/#Mental-model","page":"Importance Sampling","text":"Each step is:\n\npropose a (local) change\ncompute a local log-ratio (or local energy difference)\naccept/reject via the algorithm\nupdate counters and measure if needed\n\nThe core API function is accept!.","title":"Mental model"},{"category":"section","location":"importance_sampling_algorithms/#Target-distribution-and-acceptance-rule","page":"Importance Sampling","text":"Let pi(x) be the target density (or mass function) on the state space.\n\nBayesian example:\n\npi(theta) = p(theta mid mathcalD)\n\nStatistical-mechanics microstate example:\n\npi(x) = p(x mid beta) = frace^-beta E(x)Z(beta)\n\nMetropolis-Hastings acceptance is\n\nalpha(x to x) = minleft(1 fracpi(x) q(x mid x)pi(x) q(x mid x)right)\n\nFor symmetric local proposals q, this reduces to pi(x)  pi(x).","title":"Target distribution and acceptance rule"},{"category":"section","location":"importance_sampling_algorithms/#Unified-view:-Bayesian-and-statistical-physics-targets","page":"Importance Sampling","text":"The same sampler is used in both domains by changing only the callable log target score:\n\nBayesian inference: logweight(theta) = logposterior(theta) = loglikelihood(theta) + logprior(theta)\nStatistical mechanics: logweight(x) = -beta * E(x)\n\nIn MonteCarloX this callable is carried by the algorithm as the ensemble object, and can also be accessed as logweight(alg).\n\nBoth views are important:\n\nensemble(alg) is the architecture-level object\nlogweight(alg) is the acceptance-rule interpretation\n\nThey refer to the same callable value.","title":"Unified view: Bayesian and statistical-physics targets"},{"category":"section","location":"importance_sampling_algorithms/#Metropolis","page":"Importance Sampling","text":"","title":"Metropolis"},{"category":"section","location":"importance_sampling_algorithms/#When-to-use-it","page":"Importance Sampling","text":"default first choice for equilibrium sampling\nsimple and robust","title":"When to use it"},{"category":"section","location":"importance_sampling_algorithms/#Acceptance-intuition","page":"Importance Sampling","text":"always accept moves toward larger target weight\naccept less favorable moves with probability exp(log_ratio)","title":"Acceptance intuition"},{"category":"section","location":"importance_sampling_algorithms/#Minimal-usage","page":"Importance Sampling","text":"using Random\nusing MonteCarloX\n\nrng = MersenneTwister(1)\nlogdensity(x) = -0.5 * x^2\nalg = Metropolis(rng, logdensity)\n\nx = 0.0\nfor _ in 1:20_000\n    x_new = x + randn(alg.rng)\n    x = accept!(alg, x_new, x) ? x_new : x\nend\n\nprintln(acceptance_rate(alg))","title":"Minimal usage"},{"category":"section","location":"importance_sampling_algorithms/#Bayesian-example-(primary)","page":"Importance Sampling","text":"Coin-flip posterior with local random-walk proposals on theta:\n\npi(theta) = p(theta mid textdata) propto p(textdata mid theta) p(theta)\nimplementation target: logposterior(theta)\n\nRepository example: examples/bayesian_coin_flip.ipynb","title":"Bayesian example (primary)"},{"category":"section","location":"importance_sampling_algorithms/#Statistical-mechanics-example-(secondary)","page":"Importance Sampling","text":"Ising microstate sampling:\n\nstate x = spin configuration\ntarget pi(x) = e^-beta E(x)  Z(beta)\nlocal proposal: spin flip\n\nRepository example: examples/spin_systems/metropolis_ising2D.ipynb\n\nEnergy-variable view (same physics):\n\np(E mid beta) = fracOmega(E) e^-beta EZ(beta)\n\nwhere Omega(E) is the density of states.","title":"Statistical-mechanics example (secondary)"},{"category":"section","location":"importance_sampling_algorithms/#Glauber","page":"Importance Sampling","text":"Same proposal style as Metropolis, but uses logistic acceptance. Useful when that acceptance rule is the natural one for your dynamics or modeling convention.","title":"Glauber"},{"category":"section","location":"importance_sampling_algorithms/#HeatBath","page":"Importance Sampling","text":"Draws from local conditional probabilities instead of accept/reject. For Ising-like models this often means directly sampling local spin values from conditional weights.","title":"HeatBath"},{"category":"section","location":"importance_sampling_algorithms/#Generalized-ensembles","page":"Importance Sampling","text":"These methods adapt or use non-canonical weights to improve exploration.","title":"Generalized ensembles"},{"category":"section","location":"importance_sampling_algorithms/#Multicanonical","page":"Importance Sampling","text":"keeps a histogram of visited bins\nupdates tabulated log-weights from histogram information\nuseful for broad energy exploration and barrier crossing\n\nusing Random\nusing MonteCarloX\n\nlw = BinnedObject(-20:2:20, 0.0)\nalg = Multicanonical(MersenneTwister(2), lw)\n\nset!(ensemble(alg), -10:2:10, x -> 0.0)\n# run your update loop with accept!(alg, x_new, x_old)\n# then call update!(ensemble(alg))","title":"Multicanonical"},{"category":"section","location":"importance_sampling_algorithms/#Wang-Landau","page":"Importance Sampling","text":"updates log-density-of-states estimate at visited bins\nprogressively refines modification factor (logf via update!(ensemble(alg)) between stages)\n\nusing Random\nusing MonteCarloX\n\nlw = BinnedObject(-20:2:20, 0.0)\nalg = WangLandau(MersenneTwister(3), lw; logf=1.0)\n\n# in your loop: accept!(alg, x_new, x_old)\n# between stages: update!(alg)","title":"Wang-Landau"},{"category":"section","location":"importance_sampling_algorithms/#Choosing-quickly","page":"Importance Sampling","text":"Start with Metropolis for standard equilibrium sampling.\nUse HeatBath when conditional local probabilities are natural and cheap.\nUse Multicanonical or WangLandau when canonical sampling gets stuck or explores too narrowly.","title":"Choosing quickly"},{"category":"section","location":"importance_sampling_algorithms/#Example-map-(algorithm-application)","page":"Importance Sampling","text":"Bayesian scalar posterior (Metropolis): examples/bayesian_coin_flip.ipynb\nBayesian regression posterior (Metropolis): examples/house_price_prediction.ipynb\nCanonical spin sampling (Metropolis): examples/spin_systems/metropolis_ising2D.ipynb\nGeneralized-ensemble exploration (Multicanonical, WangLandau):\nexamples/spin_systems/muca_ising2D.ipynb\nexamples/muca_LDT_gaussian_rngs.ipynb","title":"Example map (algorithm ↔ application)"},{"category":"section","location":"importance_sampling_algorithms/#API-reference","page":"Importance Sampling","text":"","title":"API reference"},{"category":"type","location":"importance_sampling_algorithms/#MonteCarloX.AbstractImportanceSampling","page":"Importance Sampling","text":"AbstractImportanceSampling <: AbstractAlgorithm\n\nBase type for importance-sampling algorithms.\n\n\n\n\n\n","title":"MonteCarloX.AbstractImportanceSampling"},{"category":"type","location":"importance_sampling_algorithms/#MonteCarloX.AbstractMetropolis","page":"Importance Sampling","text":"AbstractMetropolis <: AbstractImportanceSampling\n\nBase type for Metropolis-family samplers where acceptance is naturally computed from a local state difference (e.g. ΔE).\n\n\n\n\n\n","title":"MonteCarloX.AbstractMetropolis"},{"category":"type","location":"importance_sampling_algorithms/#MonteCarloX.AbstractHeatBath","page":"Importance Sampling","text":"AbstractHeatBath <: AbstractAlgorithm\n\nBase type for heat-bath style algorithms.\n\n\n\n\n\n","title":"MonteCarloX.AbstractHeatBath"},{"category":"type","location":"importance_sampling_algorithms/#MonteCarloX.ImportanceSampling","page":"Importance Sampling","text":"ImportanceSampling <: AbstractImportanceSampling\n\nGeneric importance-sampling algorithm that operates on full-state acceptance arguments (x_new, x_old) using a callable ensemble.\n\nThe callable may be a function or a log-weight object and should return a scalar score such as a log density / log weight.\n\nConceptual API expectations:\n\nensemble(alg) returns the architectural ensemble object carried by the algorithm.\nlogweight(alg) returns a callable score object/function derived from that ensemble.\nAcceptance logic uses score differences from logweight.\n\nUnified view:\n\nBayesian inference: logweight(theta) = logposterior(theta)\nStatistical mechanics: logweight(x) = -beta * E(x)\n\nBoth are represented identically as ensemble-provided logweight callables.\n\n\n\n\n\n","title":"MonteCarloX.ImportanceSampling"},{"category":"method","location":"importance_sampling_algorithms/#MonteCarloX.ensemble-Tuple{AbstractImportanceSampling}","page":"Importance Sampling","text":"ensemble(alg::AbstractImportanceSampling)\n\nReturn the ensemble object carried by an importance-sampling algorithm.\n\nThis is the canonical accessor in the ensemble-first API. Operationally, this object defines the logweight used in acceptance.\n\n\n\n\n\n","title":"MonteCarloX.ensemble"},{"category":"method","location":"importance_sampling_algorithms/#MonteCarloX.logweight-Tuple{AbstractImportanceSampling}","page":"Importance Sampling","text":"logweight(alg::AbstractImportanceSampling)\n\nReturn the algorithm ensemble via a logweight-oriented alias. Equivalent to ensemble(alg).\n\nUse this accessor when reasoning about acceptance formulas.\n\n\n\n\n\n","title":"MonteCarloX.logweight"},{"category":"method","location":"importance_sampling_algorithms/#MonteCarloX.logweight-Tuple{AbstractEnsemble}","page":"Importance Sampling","text":"logweight(ens::AbstractEnsemble)\n\nReturn a callable logweight object/function for an ensemble. Concrete ensembles must implement this.\n\n\n\n\n\n","title":"MonteCarloX.logweight"},{"category":"method","location":"importance_sampling_algorithms/#MonteCarloX.logweight-Tuple{AbstractEnsemble, Any}","page":"Importance Sampling","text":"logweight(ens::AbstractEnsemble, x)\n\nEvaluate logweight on state/value x. Concrete ensembles should provide this directly or rely on a callable from logweight(ens).\n\n\n\n\n\n","title":"MonteCarloX.logweight"},{"category":"type","location":"importance_sampling_algorithms/#MonteCarloX.Metropolis","page":"Importance Sampling","text":"Metropolis <: AbstractMetropolis\n\nMetropolis algorithm for importance sampling.\n\nThe Metropolis algorithm samples from a probability distribution  proportional to exp(log_weight) using an accept/reject criterion.\n\nUnified view:\n\nBayesian inference: logweight(theta) = logposterior(theta)\nStatistical mechanics: logweight(x) = -beta * E(x)\n\nBoth are passed as the same callable ensemble score. In other words, the algorithm ensemble defines the operative logweight.\n\nFields\n\nrng::AbstractRNG: Random number generator\nensemble: Callable ensemble score (function or weight object)\nsteps::Int: Total number of steps attempted\naccepted::Int: Number of accepted steps\n\nExamples\n\n# Create with Boltzmann weight\nalg = Metropolis(Random.default_rng(), β=2.0)\n\n# Create with Bayesian log-posterior\nlogposterior(theta) = loglikelihood(theta) + logprior(theta)\nalg = Metropolis(Random.default_rng(), logposterior)\n\n# Create with custom callable score\nalg = Metropolis(Random.default_rng(), x -> -0.5 * x^2)\n\n# Create with a weight object\nens = BoltzmannEnsemble(β=1.5)\nalg = Metropolis(Random.default_rng(), ens)\n\n# Create with a tabulated or custom ensemble\nens = FunctionEnsemble(x -> -0.5 * x^2)\nalg = Metropolis(Random.default_rng(), ens)\n\n\n\n\n\n","title":"MonteCarloX.Metropolis"},{"category":"type","location":"importance_sampling_algorithms/#MonteCarloX.Glauber","page":"Importance Sampling","text":"Glauber <: AbstractMetropolis\n\nGlauber sampler with logistic acceptance rule.\n\nUses the same proposal interface and log-ratio as Metropolis-family algorithms, but acceptance is:\n\np_accept = 1 / (1 + exp(-log_ratio))\n\n\n\n\n\n","title":"MonteCarloX.Glauber"},{"category":"type","location":"importance_sampling_algorithms/#MonteCarloX.HeatBath","page":"Importance Sampling","text":"HeatBath <: AbstractHeatBath\n\nHeat-bath sampler parameters.\n\nFor Ising-like systems, updates draw directly from the local conditional probability using inverse temperature β.\n\n\n\n\n\n","title":"MonteCarloX.HeatBath"},{"category":"function","location":"importance_sampling_algorithms/#MonteCarloX.accept!","page":"Importance Sampling","text":"accept!(alg::AbstractImportanceSampling, x_new, x_old)\n\nEvaluate acceptance criterion for importance sampling with differences.\n\nUpdates step and acceptance counters in the algorithm. Returns true if the move is accepted based on the Metropolis criterion:\n\nAccept if log_ratio > 0 (new state has higher weight)\nAccept with probability exp(log_ratio) otherwise\n\nThis is the core accept/reject step used by all importance sampling algorithms.\n\n\n\n\n\naccept!(alg::AbstractMetropolis, delta_state)\n\nMetropolis-family acceptance using a local state difference.\n\n\n\n\n\naccept!(alg::ImportanceSampling{<:WangLandauEnsemble}, x_new, x_old)\n\nPerform Metropolis acceptance and apply Wang-Landau local adaptation at the visited state by updating the tabulated logweight.\n\n\n\n\n\n","title":"MonteCarloX.accept!"},{"category":"function","location":"importance_sampling_algorithms/#MonteCarloX.acceptance_rate","page":"Importance Sampling","text":"acceptance_rate(alg::AbstractImportanceSampling)\n\nCalculate the acceptance rate of the algorithm.\n\nReturns the fraction of accepted moves: accepted/steps. Returns 0.0 if no steps have been attempted yet.\n\n\n\n\n\n","title":"MonteCarloX.acceptance_rate"},{"category":"method","location":"importance_sampling_algorithms/#MonteCarloX.reset!-Tuple{AbstractImportanceSampling}","page":"Importance Sampling","text":"reset!(alg::AbstractImportanceSampling)\n\nReset step and acceptance counters to zero.\n\nUseful when you want to measure acceptance rate for a specific run phase without previous history.\n\n\n\n\n\n","title":"MonteCarloX.reset!"},{"category":"function","location":"importance_sampling_algorithms/#MonteCarloX.Multicanonical","page":"Importance Sampling","text":"Multicanonical([rng,] bins; init=0.0)\n\nCreate a generic ImportanceSampling algorithm with a MulticanonicalEnsemble built from bins.\n\nIf rng is not provided, the global RNG will be used.\n\n\n\n\n\nMulticanonical([rng,] ens::MulticanonicalEnsemble)\n\nWrap an existing multicanonical logweight in a generic ImportanceSampling algorithm.\n\nIf rng is not provided, the global RNG will be used.\n\n\n\n\n\n","title":"MonteCarloX.Multicanonical"},{"category":"function","location":"importance_sampling_algorithms/#MonteCarloX.WangLandau","page":"Importance Sampling","text":"WangLandau([rng,] bins_or_logweight; init=0.0, logf=1.0)\n\nCreate a generic ImportanceSampling algorithm with a WangLandauEnsemble built from bins_or_logweight. If rng is not provided, the global RNG will be used.\n\n\n\n\n\n","title":"MonteCarloX.WangLandau"},{"category":"method","location":"importance_sampling_algorithms/#MonteCarloX.update!-Tuple{AbstractEnsemble, Vararg{Any}}","page":"Importance Sampling","text":"update!(ens::AbstractEnsemble, args...; kwargs...)\n\nPerform in-place adaptation/update of an ensemble. Concrete ensembles must specialize this when supported.\n\n\n\n\n\n","title":"MonteCarloX.update!"},{"category":"method","location":"importance_sampling_algorithms/#MonteCarloX.update!-Tuple{WangLandauEnsemble}","page":"Importance Sampling","text":"update!(e::WangLandauEnsemble; power=0.5)\n\nUpdate Wang-Landau schedule by scaling the modification factor: logf <- power * logf with default power=0.5.\n\n\n\n\n\n","title":"MonteCarloX.update!"},{"category":"section","location":"generated/hawkes_process/#Hawkes-Process-(Self-Exciting-Point-Process)","page":"Hawkes Process (Self-Exciting Point Process)","text":"The Hawkes process is a self-exciting point process where each event increases the instantaneous rate, which then decays exponentially:\n\nlambda(t) = lambda_0 + sum_t_i  t alpha expleft(-fract - t_itauright)\n\nThe process is stationary iff the branching ratio n = alphatau  1, giving mean intensity langlelambdarangle = lambda_0(1 - alphatau).\n\nWe simulate using the inhomogeneous Poisson thinning algorithm (Lewis & Shedler 1979) via MonteCarloX's next_time.\n\nusing Random, Plots\nusing MonteCarloX: next_time","title":"Hawkes Process (Self-Exciting Point Process)"},{"category":"section","location":"generated/hawkes_process/#Simulation","page":"Hawkes Process (Self-Exciting Point Process)","text":"function hawkes_thinning(τ, λ0, α; T_max=100.0, seed=42)\n    rng     = MersenneTwister(seed)\n    samples = Float64[]\n    while true\n        t_now      = isempty(samples) ? 0.0 : samples[end]\n        excitation = sum(α * exp(-(t_now - t) / τ) for t in samples; init=0.0)\n        λ_max      = λ0 + excitation\n        λ_elapsed(s) = λ0 + excitation * exp(-s / τ)\n        t_next     = t_now + next_time(rng, λ_elapsed, λ_max)\n        t_next > T_max && break\n        push!(samples, t_next)\n    end\n    return samples\nend","title":"Simulation"},{"category":"section","location":"generated/hawkes_process/#Parameters-and-analytical-benchmarks","page":"Hawkes Process (Self-Exciting Point Process)","text":"τ, λ0, α = 1.0, 0.2, 0.5          # branching ratio α/τ = 0.5 < 1 (stationary regime)\nλ_ana  = λ0 / (1 - α/τ)           # mean intensity\nΔt_ana = 1 / λ_ana                # mean inter-event time\nT_max  = 10_000 * Δt_ana\nsamples = hawkes_thinning(τ, λ0, α; T_max)\nλ_emp  = length(samples) / T_max\nΔt_emp = sum(diff(samples)) / length(diff(samples))\nprintln(\"          analytical   empirical\")\nprintln(\"  λ     :  $(round(λ_ana;  digits=3))        $(round(λ_emp;  digits=3))\")\nprintln(\"  ⟨Δt⟩  :  $(round(Δt_ana; digits=3))        $(round(Δt_emp; digits=3))\")","title":"Parameters and analytical benchmarks"},{"category":"section","location":"generated/hawkes_process/#Plots","page":"Hawkes Process (Self-Exciting Point Process)","text":"t_grid = range(max(0, T_max - 100), T_max; length=1000)\nλ_grid = [λ0 + sum(α * exp(-(t - t0) / τ) for t0 in samples if t0 < t; init=0.0) for t in t_grid]\np1 = plot(t_grid, λ_grid; color=:steelblue, lw=1.5, label=\"λ(t)\",\n          xlabel=\"Time\", ylabel=\"λ(t)\", legend=:topright)\nxlims!(p1, minimum(t_grid), maximum(t_grid))\nhline!(p1, [λ_ana]; color=:green, ls=:dash, lw=1.5, label=\"⟨λ⟩ analytical\")\nvline!(p1, samples; color=:crimson, alpha=0.3, lw=0.8, label=nothing)\n\ndt     = diff(samples)\nt_plot = range(0, maximum(dt) * 1.5; length=200)\np2 = histogram(dt; bins=30, normalize=:pdf, alpha=0.6, color=:crimson,\n               label=\"Simulated Δt\", xlabel=\"Inter-event time Δt\", ylabel=\"Density\")\nplot!(p2, t_plot, λ_ana .* exp.(-λ_ana .* t_plot);\n      color=:green, ls=:dash, lw=2, label=\"Exp(λ_ana) — reference\")\nplot(p1, p2; layout=(2, 1), size=(700, 520))\n\n\n\nThis page was generated using Literate.jl.","title":"Plots"},{"category":"section","location":"generated/muca_BlumeCapel/#Multicanonical-Sampling-of-the-Blume-Capel-Model","page":"Multicanonical sampling: Blume-Capel","text":"Illustration of multicanonical sampling in only part of the Hamiltonian. Specifically, the Hamiltonian of the Blume-Capel model reads\n\n   H = -Jsum_ijs_i s_j + Deltasum_i s_i^2\n\nThe spin-spin interaction remains in the canonical (Boltzmann) ensemble while we construct a multicanonical ensemble for the crystal-field term. Depending on the temperature, a change in Delta induces no transition, a second-order, or a first-order phase transition.\n\nusing Random, StatsBase\nusing MonteCarloX, SpinSystems\nusing Plots, ProgressMeter","title":"Multicanonical Sampling of the Blume-Capel Model"},{"category":"section","location":"generated/muca_BlumeCapel/#CI-parameters","page":"Multicanonical sampling: Blume-Capel","text":"const CI_MODE = get(ENV, \"MCX_SMOKE\", get(ENV, \"MCX_CI\", \"false\")) == \"true\"\n\nnum_iter           = CI_MODE ? 3       : 20\nthermalization_steps = CI_MODE ? 100   : 10_000\nrecording_steps    = CI_MODE ? 1_000   : 1_000_000;\nnothing #hide","title":"CI parameters"},{"category":"section","location":"generated/muca_BlumeCapel/#Parameters","page":"Multicanonical sampling: Blume-Capel","text":"L   = 8\nT   = 0.9\nsys = BlumeCapel([L, L]);\nnothing #hide","title":"Parameters"},{"category":"section","location":"generated/muca_BlumeCapel/#Custom-ensemble","page":"Multicanonical sampling: Blume-Capel","text":"We combine a Boltzmann weight for the pairwise interaction with a multicanonical weight for the crystal-field term sum_i s_i^2. The CustomEnsemble routes each contribution to the appropriate ensemble.\n\nmutable struct CustomEnsemble <: AbstractEnsemble\n    pair          :: BoltzmannEnsemble\n    spin2         :: MulticanonicalEnsemble\n    record_visits :: Bool\nend\n\n@inline function MonteCarloX.logweight(lw::CustomEnsemble, H::Tuple{<:Real,<:Real})\n    return MonteCarloX.logweight(lw.pair, H[1]) + MonteCarloX.logweight(lw.spin2, H[2])\nend\n\n@inline MonteCarloX.should_record_visit(lw::CustomEnsemble) = lw.record_visits\n\n@inline function MonteCarloX.record_visit!(lw::CustomEnsemble, H_vis::Tuple{<:Real,<:Real})\n    MonteCarloX.record_visit!(lw.spin2, H_vis[2])\n    return nothing\nend\n\n@inline function reset_histogram!(lw::CustomEnsemble)\n    fill!(lw.spin2.histogram.values, zero(eltype(lw.spin2.histogram.values)))\n    return nothing\nend\n\n@inline reset_histogram!(alg::AbstractImportanceSampling) =\n    reset_histogram!(MonteCarloX.ensemble(alg))\n\nens = CustomEnsemble(\n    BoltzmannEnsemble(T=T),\n    MulticanonicalEnsemble(0:1:length(sys.spins)),\n    true,\n);\nnothing #hide","title":"Custom ensemble"},{"category":"section","location":"generated/muca_BlumeCapel/#Spin-flip","page":"Multicanonical sampling: Blume-Capel","text":"We implement a custom spin_flip! for the Blume-Capel model that evaluates the two-component observable (Jsum s_i s_j sum s_i^2) and passes it to accept! as a tuple — the CustomEnsemble routes each component to the correct acceptance weight.\n\nfunction spin_flip!(sys::SpinSystems.AbstractBlumeCapel, alg::AbstractImportanceSampling)\n    i     = pick_site(alg.rng, length(sys.spins))\n    s_new = SpinSystems._propose_state(alg.rng, sys.spins[i])\n    Δpair, Δspin, Δspin2 = SpinSystems.propose_changes(sys, i, s_new)\n    H_old = (sys.J * sys.sum_pair_interactions, sys.sum_spins2)\n    H_new = (H_old[1] + sys.J * Δpair, H_old[2] + Δspin2)\n    accept!(alg, H_new, H_old) && modify!(sys, i, s_new, Δpair, Δspin, Δspin2)\n    return nothing\nend","title":"Spin flip"},{"category":"section","location":"generated/muca_BlumeCapel/#Multicanonical-iteration","page":"Multicanonical sampling: Blume-Capel","text":"Each iteration thermalizes the system, resets the histogram, accumulates statistics, and updates the multicanonical weights via the Wang-Landau rule.\n\nrng = Xoshiro(42)\nalg = Metropolis(rng, ens)\n\nhistograms = Vector{typeof(ensemble(alg).spin2.histogram)}()\nlogweights = Vector{typeof(ensemble(alg).spin2.logweight)}()\nacceptrate = Float64[]\n\n@showprogress 1 \"Iterating MUCA...\" for _ in 1:num_iter\n    for _ in 1:thermalization_steps; spin_flip!(sys, alg); end\n    reset!(alg)\n    reset_histogram!(alg)\n    for _ in 1:recording_steps;     spin_flip!(sys, alg); end\n    MonteCarloX.update!(ensemble(alg).spin2)\n    push!(histograms, deepcopy(ensemble(alg).spin2.histogram))\n    push!(logweights, deepcopy(ensemble(alg).spin2.logweight))\n    push!(acceptrate, acceptance_rate(alg))\nend","title":"Multicanonical iteration"},{"category":"section","location":"generated/muca_BlumeCapel/#Convergence","page":"Multicanonical sampling: Blume-Capel","text":"The acceptance rate should stabilise as the weights converge to flat.\n\nplot(acceptrate; xlabel=\"Iteration\", ylabel=\"Acceptance rate\",\n     label=nothing, size=(600, 220), margin=5Plots.mm, ylims=(0,1))","title":"Convergence"},{"category":"section","location":"generated/muca_BlumeCapel/#Histograms-and-log-weights","page":"Multicanonical sampling: Blume-Capel","text":"Each iteration refines the estimated log-DOS for sum_i s_i^2. Converged iterations should show a flat histogram and a smooth log-weight.\n\nfunction plot_histograms_and_logweights(xlabel, hist_vec, lw_vec; title_prefix=\"\")\n    n    = length(hist_vec)\n    cols = palette(:viridis, max(n, 2))[1:n]\n    xs   = get_centers(hist_vec[1])\n    i0   = 1\n\n    p1 = plot(xs, hist_vec[1].values; lw=2, color=cols[1],\n              xlabel=xlabel, ylabel=\"counts\",\n              title=\"$(title_prefix) histograms\", legend=false,\n              ylims=(0, maximum(hist_vec[1].values) * 1.2))\n    for i in 2:n\n        plot!(p1, xs, hist_vec[i].values; lw=2, color=cols[i])\n    end\n\n    p2 = plot(xlabel=xlabel, ylabel=\"-log w\",\n              title=\"$(title_prefix) log-weights\", legend=false)\n    for i in 1:n\n        plot!(p2, xs, -lw_vec[i].values .+ lw_vec[i].values[i0]; lw=2, color=cols[i])\n    end\n\n    return plot(p1, p2; layout=(@layout([a b])), size=(960, 320), margin=4Plots.mm)\nend\n\nplot_histograms_and_logweights(\"∑sᵢ²\", histograms, logweights; title_prefix=\"MUCA\")\n\n\n\nThis page was generated using Literate.jl.","title":"Histograms and log-weights"},{"category":"section","location":"generated/eight_schools/#Hierarchical-Bayesian-Inference:-The-Eight-Schools-Problem","page":"Hierarchical sampling: Eight Schools","text":"The eight schools problem (Rubin, 1981) is a canonical example of hierarchical Bayesian modelling. A test-preparation program was run independently in 8 schools; each school measured a mean score improvement y_n with standard error sigma_n. The effects vary widely and their standard errors are large — so neither pooling all schools nor treating them independently is appropriate.\n\nThe hierarchical solution: assume each school's true improvement theta_n is drawn from a shared population distribution, so information is partially pooled across schools.\n\ntheta_n sim mathcalN(mu tau) qquad\ny_n sim mathcalN(theta_n sigma_n)\n\nwith priors mu sim mathcalN(0 10) and logtau sim mathcalN(5 1), following the TensorFlow Probability implementation.\n\nusing Random, Statistics, Distributions\nusing StatsBase, LinearAlgebra\nusing MonteCarloX\nusing Plots","title":"Hierarchical Bayesian Inference: The Eight Schools Problem"},{"category":"section","location":"generated/eight_schools/#CI-parameters","page":"Hierarchical sampling: Eight Schools","text":"In smoke-test mode (CI) we reduce the number of samples to keep the run fast. Full results require n_burn=10_000, n_samples=100_000.\n\nconst CI_MODE = get(ENV, \"MCX_SMOKE\", get(ENV, \"MCX_CI\", \"false\")) == \"true\"\n\nn_burn    = CI_MODE ? 200     : 10_000\nn_samples = CI_MODE ? 500     : 100_000\nthin      = CI_MODE ? 1       : 10","title":"CI parameters"},{"category":"section","location":"generated/eight_schools/#Data","page":"Hierarchical sampling: Eight Schools","text":"y_schools = [28.0,  8.0, -3.0,  7.0, -1.0,  1.0, 18.0, 12.0]  ## mean score improvements\nσ_schools = [15.0, 10.0, 16.0, 11.0,  9.0, 11.0, 10.0, 18.0]  ## standard errors\nJ         = length(y_schools)\n\nprintln(\"School effects  : \", y_schools)\nprintln(\"Standard errors : \", σ_schools)","title":"Data"},{"category":"section","location":"generated/eight_schools/#Model","page":"Hierarchical sampling: Eight Schools","text":"We sample logtau directly to keep the sampler unconstrained. The prior logtau sim mathcalN(51) is equivalent to a textLogNormal(51) prior on tau — no Jacobian needed.\n\nThe PyMC/Stan canonical version uses tau sim textHalfCauchy(05) instead, which places more mass near zero and favours stronger pooling.\n\nThe full state vector is mu logtau theta_1ldotstheta_8.\n\nget_μ(s)    = s[1]\nget_logτ(s) = s[2]\nget_θ(s)    = s[3:end]\n\nfunction logposterior(s)\n    μ, logτ, θ = get_μ(s), get_logτ(s), get_θ(s)\n    τ   = exp(logτ)\n    lp  = logpdf(Normal(0, 10), μ)                    ## population mean\n    lp += logpdf(Normal(5, 1),  logτ)                 ## log τ ~ N(5,1)\n    lp += sum(logpdf.(Normal(μ, τ), θ))               ## school effects\n    lp += sum(logpdf.(Normal.(θ, σ_schools), y_schools))  ## likelihood\n    return lp\nend\n\ns0 = [mean(y_schools); log(std(y_schools)); copy(y_schools)]\nprintln(\"Initial log-posterior : \", round(logposterior(s0); digits=2))","title":"Model"},{"category":"section","location":"generated/eight_schools/#Metropolis-sampling","page":"Hierarchical sampling: Eight Schools","text":"We update one parameter at a time with a uniform random-walk proposal. Step sizes are tuned separately for (mu logtau) and the school effects theta_n.\n\nfunction update!(s, alg, Δ)\n    i     = rand(alg.rng, 1:length(s))\n    s_new = copy(s)\n    s_new[i] += rand(alg.rng, Uniform(-Δ[i], Δ[i]))\n    accept!(alg, s_new, s) && (s[i] = s_new[i])\nend\n\nfunction run_metropolis(logposterior, s0; seed=42)\n    rng     = Xoshiro(seed)\n    alg     = Metropolis(rng, logposterior)\n    s       = copy(s0)\n    Δ       = vcat([2.0, 2.0], fill(5.0, length(s)-2))\n    samples = zeros(length(s), n_samples)\n    for _ in 1:n_burn\n        update!(s, alg, Δ)\n    end\n    for k in 1:n_samples*thin\n        update!(s, alg, Δ)\n        k % thin == 0 && (samples[:, k÷thin] = s)\n    end\n    return samples, alg\nend\n\nsamples, alg = run_metropolis(logposterior, s0)\n\nprintln(\"Acceptance rate   : \", round(acceptance_rate(alg); digits=3))\nprintln(\"Samples collected : \", size(samples, 2))","title":"Metropolis sampling"},{"category":"section","location":"generated/eight_schools/#Convergence-check","page":"Hierarchical sampling: Eight Schools","text":"The log-posterior trace should be stationary with no visible trend.\n\nlps = [logposterior(samples[:, i]) for i in 1:size(samples,2)]\nplot(lps; xlabel=\"Iteration\", ylabel=\"Log-posterior\",\n     title=\"Convergence trace\", size=(700, 220),\n     margin=5Plots.mm, legend=false)","title":"Convergence check"},{"category":"section","location":"generated/eight_schools/#Results","page":"Hierarchical sampling: Eight Schools","text":"Posterior medians and 95% credible intervals for all parameters. Partial pooling shrinks extreme school effects toward the population mean mu.\n\nμ_s = samples[1, :]\nτ_s = exp.(samples[2, :])\nθ_s = [samples[2+i, :] for i in 1:J]\n\nprintln(\"Parameter   median     95% CI\")\nprintln(\"─────────────────────────────────────\")\nfor (name, s) in vcat([(\"μ\", μ_s), (\"τ\", τ_s)],\n                      [(\"θ[$(i)]\", θ_s[i]) for i in 1:J])\n    lo, hi = round.(quantile(s, [0.025, 0.975]); digits=1)\n    println(rpad(name, 10), rpad(round(median(s); digits=1), 10),\n            \"[$(lo), $(hi)]\")\nend","title":"Results"},{"category":"section","location":"generated/eight_schools/#Posterior-marginals","page":"Hierarchical sampling: Eight Schools","text":"Each panel shows the posterior histogram against the prior curve. The hierarchical prior on theta_n uses the posterior medians of (mu tau) as its parameters, illustrating the learned population distribution.\n\nfunction marginal_panel(s, prior, xlabel)\n    hist = fit(Histogram, s; nbins=40)\n    dist = normalize(hist; mode=:pdf)\n    xs   = range(hist.edges[1][1], hist.edges[1][end]; length=300)\n    fig  = plot(dist; st=:bar, linewidth=0, alpha=0.6,\n                label=\"posterior\", xlabel=xlabel, ylabel=\"density\")\n    plot!(fig, xs, pdf.(prior, xs); lw=2, color=:black, label=\"prior\")\n    return fig\nend\n\nθ_prior = Normal(median(μ_s), median(τ_s))\n\npanels = [\n    marginal_panel(μ_s, Normal(0, 10),   \"μ\"),\n    marginal_panel(τ_s, LogNormal(5, 1), \"τ\"),\n]\nfor i in 1:J\n    push!(panels, marginal_panel(θ_s[i], θ_prior, \"θ[$(i)]\"))\nend\n\nplot(panels...; layout=(2, 5), size=(1100, 380), margin=4Plots.mm,\n     plot_title=\"Posterior marginals vs priors\")\n\n\n\nThis page was generated using Literate.jl.","title":"Posterior marginals"},{"category":"section","location":"#MonteCarloX.jl","page":"Getting Started","text":"MonteCarloX.jl is a modular Monte Carlo framework in Julia. It separates the sampling algorithm from the system under study: the user defines the system state and proposes changes; MonteCarloX provides the acceptance criterion. Because the algorithm is independent of the model, every simulation becomes a template — replacing the system yields a new application without modifying the algorithmic loop.","title":"MonteCarloX.jl"},{"category":"section","location":"#Separation-of-concerns","page":"Getting Started","text":"A Monte Carlo simulation in this framework consists of two parts:\n\nProblem-specific (provided by the user): the system state and a rule for proposing changes.\nAlgorithms (provided by MonteCarloX): the development of the Markov Chain that can vary from simple to complex.\n\nFor discrete-state sampling, the central interface is accept!(algorithm, x_new, x_old). For continuous-time dynamics, the equivalent is advance!(algorithm, system, T), which selects event times and events from user-defined rates.\n\nThis separation keeps algorithm code model-agnostic: the same Metropolis algorithm samples a posterior distribution in Bayesian inference, an Ising model at thermal equilibrium, or any other system for which a log-weight function can be defined.\n\nBecause the user retains full control over the system definition and update rule, it is straightforward to build companion packages that provide these for entire model families. For example, SpinSystems implements states, updates, and observables for Ising and Blume-Capel models, so that a simulation reduces to choosing an algorithm and running the loop.","title":"Separation of concerns"},{"category":"section","location":"#Algorithms","page":"Getting Started","text":"MonteCarloX provides the following sampling algorithms, each usable with any system that implements the required interface:\n\nImportance sampling: Metropolis, Glauber, HeatBath — accept or reject proposed changes based on a log-weight ratio.\nFlat-histogram methods: Multicanonical, WangLandau — iteratively adapt weights to achieve uniform sampling over an order parameter, enabling access to rare configurations.\nExtended-ensemble methods: ParallelTempering, ReplicaExchange — run multiple replicas at different parameters and exchange configurations to overcome free-energy barriers.\nContinuous-time sampling: Gillespie — exact stochastic simulation via event rates.","title":"Algorithms"},{"category":"section","location":"#Examples-as-templates","page":"Getting Started","text":"The documentation includes worked examples across several domains. Each example is a self-contained simulation that serves as a template: the algorithmic structure remains unchanged when the system is replaced.\n\nBayesian inference: posterior sampling for coin flips, linear regression, hierarchical models.\nStatistical mechanics: importance sampling, multicanonical sampling, and parallel tempering for Ising and Blume-Capel models.\nStochastic processes: Poisson processes, birth-death dynamics, reversible dimerization via the Gillespie algorithm.\nLarge deviation theory: multicanonical sampling of rare fluctuations in sums of random variables and the Ornstein-Uhlenbeck process.\nInfrastructure: checkpointing and parallel chains (MPI, threads).","title":"Examples as templates"},{"category":"section","location":"#Scope","page":"Getting Started","text":"MonteCarloX provides the algorithmic core. Concrete model families (e.g., SpinSystems) are maintained as separate companion packages. This keeps the framework compact and allows independent development of new models.","title":"Scope"},{"category":"section","location":"#Related-Julia-packages","page":"Getting Started","text":"The Julia ecosystem already has several Monte Carlo packages with different goals and interfaces. If your use case is better served by a domain-specific implementation, these are useful alternatives or complements:\n\nGeneralizedMonteCarlo.jl: generalized-ensemble methods (for example multicanonical and related workflows).\nMonteCarlo.jl: quantum many-body focused Monte Carlo framework.\nCarlo.jl: lattice-model Monte Carlo toolkit with a strong focus on physics applications.\n\nOther related packages (grouped by common use cases):\n\nBayesian inference and MCMC:\n\n- [Turing.jl](https://github.com/TuringLang/Turing.jl)\n- [AbstractMCMC.jl](https://github.com/TuringLang/AbstractMCMC.jl)\n- [AdvancedMH.jl](https://github.com/TuringLang/AdvancedMH.jl)\n- [AdvancedHMC.jl](https://github.com/TuringLang/AdvancedHMC.jl)\n- [DynamicHMC.jl](https://github.com/tpapp/DynamicHMC.jl)\n- [BAT.jl](https://github.com/bat/BAT.jl)\n- [Gen.jl](https://github.com/probcomp/Gen.jl)\n\nMonte Carlo integration and low-discrepancy sampling:\n\n- [Cuba.jl](https://github.com/giordano/Cuba.jl)\n- [QuasiMonteCarlo.jl](https://github.com/SciML/QuasiMonteCarlo.jl)\n- [SpinMC](https://github.com/fbuessen/SpinMC.jl)\n\nUncertainty propagation with particle arithmetic:\n\n- [MonteCarloMeasurements.jl](https://github.com/baggepinnen/MonteCarloMeasurements.jl)\n\nMonteCarloX stays focused on compact, model-agnostic algorithmic building blocks, while these packages offer specialized ecosystems for their target domains.","title":"Related Julia packages"},{"category":"section","location":"#Random-number-generators","page":"Getting Started","text":"MonteCarloX works with any Julia AbstractRNG.\n\nPrefer Xoshiro as a modern default for new projects.\nUse MersenneTwister when compatibility with existing workflows is needed.\n\nBecause RNG is passed directly to algorithms, changing RNG is a one-line change.","title":"Random number generators"},{"category":"section","location":"measurements/#Measurements","page":"Measurements","text":"MonteCarloX separates what you measure from when you measure it. Measurement and Measurements are convenience helpers — they are not required for running MonteCarloX algorithms. You can always collect observables manually in your simulation loop.","title":"Measurements"},{"category":"section","location":"measurements/#Building-blocks","page":"Measurements","text":"Measurement: one observable paired with one data container\nMeasurements: named collection with a shared schedule\nschedule types:\nIntervalSchedule\nPreallocatedSchedule","title":"Building blocks"},{"category":"section","location":"measurements/#Step-based-measurements-(common-in-equilibrium-loops)","page":"Measurements","text":"using MonteCarloX\n\nmeasurements = Measurements([\n    :energy        => energy        => Float64[],\n    :magnetization => magnetization => Float64[],\n], interval=10)\n\n# in your loop:\n# measure!(measurements, sys, step)\n\nThis records every 10 loop steps.","title":"Step-based measurements (common in equilibrium loops)"},{"category":"section","location":"measurements/#Time-based-measurements-(common-in-Gillespie-loops)","page":"Measurements","text":"using MonteCarloX\n\ntimes = collect(0.0:0.1:10.0)\nmeasurements = Measurements([\n    :N => (state -> state[:N]) => Float64[],\n], times)\n\n# in your loop:\n# measure!(measurements, state, t)\n# stop criterion: is_complete(measurements)\n\nPreallocatedSchedule handles event skipping by consuming all crossed checkpoints.","title":"Time-based measurements (common in Gillespie loops)"},{"category":"section","location":"measurements/#Data-access-and-reset","page":"Measurements","text":"measurements[:energy].data — raw storage\ndata(measurements, :energy) — convenience accessor\nreset!(measurements) — clears data and restarts schedule state","title":"Data access and reset"},{"category":"section","location":"measurements/#Integrated-autocorrelation-time","page":"Measurements","text":"For replica-exchange or MCMC tuning, MonteCarloX provides a compact integrated autocorrelation-time estimate:\n\nusing MonteCarloX\n\nenergies = data(measurements, :energy)\ntauE = integrated_autocorrelation_time(energies)\n# convenience alias:\n# tauE = tau_int(energies)\n\nThis estimates\n\n\tau_mathrmint = frac12 + sum_tge 1 C(t)\n\nwith a self-consistent lag window. Use it as a practical tuning signal for local decorrelation effort; short traces can be noisy. By default, the maximal lag is capped at floor(n/2).","title":"Integrated autocorrelation time"},{"category":"section","location":"measurements/#API-reference","page":"Measurements","text":"","title":"API reference"},{"category":"type","location":"measurements/#MonteCarloX.Measurement","page":"Measurements","text":"Measurement{F,T}\n\nA measurement consisting of an observable function and a data container.\n\nFields\n\nobservable::F: Function that extracts a value from the system\ndata::T: Container for storing measurements (Vector, Histogram, etc.)\n\n\n\n\n\n","title":"MonteCarloX.Measurement"},{"category":"type","location":"measurements/#MonteCarloX.Measurements","page":"Measurements","text":"Measurements{K,S<:MeasurementSchedule}\n\nContainer for multiple measurements with a shared schedule.\n\nFields\n\nmeasurements::Dict{K, Measurement}: Dictionary of named measurements\nschedule::S: Measurement schedule\n\n\n\n\n\n","title":"MonteCarloX.Measurements"},{"category":"type","location":"measurements/#MonteCarloX.MeasurementSchedule","page":"Measurements","text":"MeasurementSchedule\n\nAbstract type for different measurement scheduling strategies.\n\n\n\n\n\n","title":"MonteCarloX.MeasurementSchedule"},{"category":"type","location":"measurements/#MonteCarloX.IntervalSchedule","page":"Measurements","text":"IntervalSchedule <: MeasurementSchedule\n\nSchedule measurements at regular intervals.\n\nFields\n\ninterval::Float64: Time/step interval between measurements\n_checkpoint::Float64: Internal checkpoint for next measurement\n\n\n\n\n\n","title":"MonteCarloX.IntervalSchedule"},{"category":"type","location":"measurements/#MonteCarloX.PreallocatedSchedule","page":"Measurements","text":"PreallocatedSchedule <: MeasurementSchedule\n\nSchedule measurements at pre-specified times.\n\nFields\n\ntimes::Vector{Float64}: Sorted vector of measurement times\ncheckpoint_idx::Int: Current index in times vector\n\n\n\n\n\n","title":"MonteCarloX.PreallocatedSchedule"},{"category":"function","location":"measurements/#MonteCarloX.measure!","page":"Measurements","text":"measure!(measurement::Measurement, sys; kwargs...)\n\nPerform a single measurement by evaluating the observable on the system and storing the result.\n\n\n\n\n\nmeasure!(measurements::Measurements{K, IntervalSchedule}, sys, t; kwargs...)\n\nPerform measurements at regular intervals (indefinite simulation).\n\n\n\n\n\nmeasure!(measurements::Measurements{K, PreallocatedSchedule}, sys, t; kwargs...)\n\nPerform measurements at preallocated times (handles event skipping).\n\n\n\n\n\nmeasure!(sys, event, t)\n\nObserve system sys at time t before modify!. Default is a no-op.\n\n\n\n\n\n","title":"MonteCarloX.measure!"},{"category":"method","location":"measurements/#MonteCarloX.reset!-Tuple{Measurement}","page":"Measurements","text":"reset!(measurement::Measurement)\n\nReset a single measurement to its initial state by clearing its data container. For histogram-backed measurements this zeros the bin counts while preserving binning.\n\n\n\n\n\n","title":"MonteCarloX.reset!"},{"category":"method","location":"measurements/#MonteCarloX.reset!-Tuple{IntervalSchedule}","page":"Measurements","text":"reset!(schedule::MeasurementSchedule)\n\nReset schedule counters/checkpoints back to their initial state.\n\n\n\n\n\n","title":"MonteCarloX.reset!"},{"category":"method","location":"measurements/#MonteCarloX.reset!-Tuple{Measurements}","page":"Measurements","text":"reset!(measurements::Measurements)\n\nReset all measurement data containers and schedule state in-place.\n\n\n\n\n\n","title":"MonteCarloX.reset!"},{"category":"function","location":"measurements/#MonteCarloX.integrated_autocorrelation_time","page":"Measurements","text":"integrated_autocorrelation_time(samples; max_lag=nothing, c=5.0)\n\nEstimate the integrated autocorrelation time\n\ntau_int = 1/2 + sum_{t>=1} C(t),\n\nfor a scalar time series samples where C(t) is the normalized autocorrelation function at lag t. \n\nImplementation notes:\n\nUses a direct lag loop over centered samples.\nTruncates the sum using a self-consistent window (lag > c * tau).\nAlso truncates if the estimated normalized autocorrelation becomes non-positive.\n\nArguments\n\nsamples: scalar time series (e.g. energy trace at fixed beta).\nmax_lag: optional hard cap for the lag window. Must satisfy 1 <= max_lag <= floor(length(samples)/2).\nc: positive windowing constant for the self-consistent cutoff.\n\nReturns\n\nEstimated integrated autocorrelation time as Float64.\nReturns 0.5 for zero-variance input.\n\n\n\n\n\n","title":"MonteCarloX.integrated_autocorrelation_time"},{"category":"function","location":"measurements/#MonteCarloX.integrated_autocorrelation_times","page":"Measurements","text":"integrated_autocorrelation_times(traces; min_points=2, max_lag=nothing, c=5.0)\n\nCompute integrated_autocorrelation_time for each trace in traces. Entries with fewer than min_points samples return NaN.\n\n\n\n\n\n","title":"MonteCarloX.integrated_autocorrelation_times"},{"category":"function","location":"measurements/#MonteCarloX.tau_int","page":"Measurements","text":"tau_int(samples; kwargs...)\n\nConvenience wrapper for integrated_autocorrelation_time.\n\n\n\n\n\n","title":"MonteCarloX.tau_int"},{"category":"method","location":"measurements/#MonteCarloX.times-Union{Tuple{Measurements{K, PreallocatedSchedule}}, Tuple{K}} where K","page":"Measurements","text":"times(m::Measurements)\n\nReturn the measurement time points for preallocated schedules.\n\n\n\n\n\n","title":"MonteCarloX.times"},{"category":"method","location":"measurements/#MonteCarloX.data-Union{Tuple{K}, Tuple{Measurements{K}, K}} where K","page":"Measurements","text":"data(m::Measurements{K}, key::K)\n\nReturn the raw data container for a named measurement.\n\n\n\n\n\n","title":"MonteCarloX.data"},{"category":"function","location":"measurements/#MonteCarloX.is_complete","page":"Measurements","text":"is_complete(m::Measurements)\n\nCheck if all scheduled measurements are complete. Returns false for interval-based schedules (indefinite).\n\n\n\n\n\n","title":"MonteCarloX.is_complete"},{"category":"section","location":"generated/gillespie_birth_death/#Birth-Death-Process-with-Gillespie-Algorithm","page":"Birth-Death Process (Gillespie)","text":"The linear birth-death process is one of the simplest continuous-time stochastic models in population dynamics. Each individual reproduces at rate lambda and dies at rate mu, giving total propensities\n\nr_textbirth = lambda N qquad r_textdeath = mu N\n\nWhen lambda  mu the population grows on average; when lambda  mu it declines toward extinction; at lambda = mu it performs a critical random walk and will eventually go extinct.\n\nusing Random, StatsBase, Plots\nusing MonteCarloX","title":"Birth-Death Process with Gillespie Algorithm"},{"category":"section","location":"generated/gillespie_birth_death/#System-definition","page":"Birth-Death Process (Gillespie)","text":"mutable struct BirthDeathProcess <: AbstractSystem\n    N  :: Int\n    λ  :: Float64\n    μ  :: Float64\n    rates :: Vector{Float64}\n    function BirthDeathProcess(N0, λ, μ)\n        new(N0, λ, μ, [λ*N0, μ*N0])\n    end\nend\n\nMonteCarloX.event_source(sys::BirthDeathProcess) = sys.rates\n\nfunction MonteCarloX.modify!(sys::BirthDeathProcess, event::Int, t)\n    event == 1 ? (sys.N += 1) : (sys.N -= 1)\n    sys.rates[1] = sys.λ * sys.N   ## update in place — src reference stays valid\n    sys.rates[2] = sys.μ * sys.N\n    return nothing\nend","title":"System definition"},{"category":"section","location":"generated/gillespie_birth_death/#Single-trajectory","page":"Birth-Death Process (Gillespie)","text":"We run a single simulation at lambda = 042, mu = 040 — a slightly super-critical regime — and record the population every 0.5 time units. advance! handles the event loop internally, calling measure! before each state update and stopping when the total time is reached or all rates vanish (extinction: N = 0).\n\nsys = BirthDeathProcess(10, 0.42, 0.40)\nalg = Gillespie(MersenneTwister(42))\nT   = 100.0\n\nmeasurements = Measurements(\n    [:population => (s -> s.N) => Float64[]],\n    collect(0.0:0.5:T),\n)\nmeasure!(measurements, sys, alg.time)\n\nadvance!(alg, sys, T;\n    measure! = (sys, event, t) -> measure!(measurements, sys, t),\n)\n\npop = measurements[:population].data\nprintln(\"Final population : $(sys.N)\")\nprintln(\"Total events     : $(alg.steps)\")\nprintln(\"Mean population  : $(round(mean(pop); digits=2))\")\n\nplot(collect(0.0:0.5:T)[1:length(pop)], pop; lw=2, label=\"λ=0.42, μ=0.40\",\n     xlabel=\"Time\", ylabel=\"Population N(t)\",\n     title=\"Single birth-death trajectory\", size=(700, 260), margin=5Plots.mm)","title":"Single trajectory"},{"category":"section","location":"generated/gillespie_birth_death/#Comparison-across-birth-rates","page":"Birth-Death Process (Gillespie)","text":"Varying lambda at fixed mu = 040 illustrates the three regimes. The log scale makes exponential growth and decay linear, and reveals extinction events as trajectories dropping to zero.\n\nfunction run_birth_death(N0, λ, μ, T; seed=1)\n    sys  = BirthDeathProcess(N0, λ, μ)\n    alg  = Gillespie(MersenneTwister(seed))\n    meas = Measurements(\n        [:N => (s -> s.N) => Float64[]],\n        collect(0.0:0.5:T),\n    )\n    measure!(meas, sys, alg.time)\n    advance!(alg, sys, T;\n        measure! = (sys, event, t) -> measure!(meas, sys, t),\n    )\n    measure!(meas, sys, T)\n    return meas\nend\n\nN0     = 10\nμ      = 0.40\nT_plot = 80.0\nλs     = [0.35, 0.40, 0.45, 0.50]\n\np = plot(xlabel=\"Time\", ylabel=\"Population N(t)\",\n         title=\"Birth-death process for varying λ  (μ = $μ)\",\n         legend=:topleft, yscale=:log10,\n         size=(700, 300), margin=5Plots.mm)\n\nfor (i, λ) in enumerate(λs)\n    meas = run_birth_death(N0, λ, μ, T_plot; seed=100+i)\n    t    = MonteCarloX.times(meas)\n    y    = MonteCarloX.data(meas, :N)\n    idx  = y .> 0\n    plot!(p, t[idx], y[idx]; lw=2, label=\"λ = $λ\")\nend\np\n\nThe sub-critical trajectory (lambda = 035) goes extinct early; the super-critical ones (lambda geq 045) grow exponentially. At lambda = mu = 040 the process is critical and drifts slowly.\n\n\n\nThis page was generated using Literate.jl.","title":"Comparison across birth rates"}]
}
